import type { Spell } from '../../types';

export const ALL_SPELLS: Spell[] = [
  // CANTRIPS
  { id: 'fire-bolt', name: 'Fire Bolt', level: 0, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '120 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You hurl a mote of fire at a creature or object within range. Make a ranged spell attack against the target. On a hit, the target takes 1d10 fire damage. A flammable object hit by this spell ignites if it isn\'t being worn or carried.\n\nThis spell\'s damage increases by 1d10 when you reach 5th level (2d10), 11th level (3d10), and 17th level (4d10).', classes: ['sorcerer', 'wizard'], damageType: 'fire', tags: ['damage', 'ranged'] },
  { id: 'eldritch-blast', name: 'Eldritch Blast', level: 0, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '120 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'A beam of crackling energy streaks toward a creature within range. Make a ranged spell attack against the target. On a hit, the target takes 1d10 force damage.\n\nThe spell creates more than one beam when you reach higher levels: two beams at 5th level, three beams at 11th level, and four beams at 17th level. You can direct the beams at the same target or at different ones. Make a separate attack roll for each beam.', classes: ['warlock'], damageType: 'force', tags: ['damage', 'ranged'] },
  { id: 'sacred-flame', name: 'Sacred Flame', level: 0, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'Flame-like radiance descends on a creature that you can see within range. The target must succeed on a Dexterity saving throw or take 1d8 radiant damage. The target gains no benefit from cover for this saving throw.\n\nThe spell\'s damage increases by 1d8 when you reach 5th level (2d8), 11th level (3d8), and 17th level (4d8).', classes: ['cleric'], damageType: 'radiant', savingThrow: 'dex', tags: ['damage'] },
  { id: 'guidance', name: 'Guidance', level: 0, school: 'Divination', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You touch one willing creature. Once before the spell ends, the target can roll a d4 and add the number rolled to one ability check of its choice. It can roll the die before or after making the ability check. The spell then ends.', classes: ['cleric', 'druid'], tags: ['buff', 'utility'] },
  { id: 'mage-hand', name: 'Mage Hand', level: 0, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 action', range: '30 feet', components: ['V', 'S'], duration: '1 minute', concentration: false, ritual: false, description: 'A spectral, floating hand appears at a point you choose within range. The hand lasts for the duration or until you dismiss it as an action. The hand vanishes if it is ever more than 30 feet away from you or if you cast this spell again.\n\nYou can use your action to control the hand. You can use the hand to manipulate an object, open an unlocked door or container, stow or retrieve an item from an open container, or pour the contents out of a vial. You can move the hand up to 30 feet each time you use it.\n\nThe hand can\'t attack, activate magic items, or carry more than 10 pounds.', classes: ['bard', 'sorcerer', 'warlock', 'wizard'], tags: ['utility'] },
  { id: 'prestidigitation', name: 'Prestidigitation', level: 0, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: '10 feet', components: ['V', 'S'], duration: 'Up to 1 hour', concentration: false, ritual: false, description: 'This spell is a minor magical trick that novice spellcasters use for practice. You create one of the following magical effects within range: You create an instantaneous, harmless sensory effect, such as a shower of sparks, a puff of wind, faint musical notes, or an odd odor. You instantaneously light or snuff out a candle, a torch, or a small campfire. You instantaneously clean or soil an object no larger than 1 cubic foot. You chill, warm, or flavor up to 1 cubic foot of nonliving material for 1 hour. You make a color, a small mark, or a symbol appear on an object or a surface for 1 hour. You create a nonmagical trinket or an illusory image that can fit in your hand and that lasts until the end of your next turn.', classes: ['bard', 'sorcerer', 'warlock', 'wizard'], tags: ['utility'] },
  { id: 'minor-illusion', name: 'Minor Illusion', level: 0, school: 'Illusion', sourceBook: 'PHB', castingTime: '1 action', range: '30 feet', components: ['S', 'M'], materialComponent: 'a bit of fleece', duration: '1 minute', concentration: false, ritual: false, description: 'You create a sound or an image of an object within range that lasts for the duration. The illusion also ends if you dismiss it as an action or cast this spell again.\n\nIf you create a sound, its volume can range from a whisper to a scream. It can be your voice, someone else\'s voice, a lion\'s roar, a beating of drums, or any other sound you choose. The sound continues unabated throughout the duration, or you can make discrete sounds at different times before the spell ends.\n\nIf you create an image of an object—such as a chair, muddy footprints, or a small chest—it must be no larger than a 5-foot cube. The image can\'t create sound, light, smell, or any other sensory effect.', classes: ['bard', 'sorcerer', 'warlock', 'wizard'], tags: ['utility', 'illusion'] },
  { id: 'vicious-mockery', name: 'Vicious Mockery', level: 0, school: 'Enchantment', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You unleash a string of insults laced with subtle enchantments at a creature you can see within range. If the target can hear you (though it need not understand you), it must succeed on a Wisdom saving throw or take 1d4 psychic damage and have disadvantage on the next attack roll it makes before the end of its next turn.\n\nThis spell\'s damage increases by 1d4 when you reach 5th level (2d4), 11th level (3d4), and 17th level (4d4).', classes: ['bard'], damageType: 'psychic', savingThrow: 'wis', tags: ['damage', 'debuff'] },
  { id: 'toll-the-dead', name: 'Toll the Dead', level: 0, school: 'Necromancy', sourceBook: 'XGtE', castingTime: '1 action', range: '60 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You point at one creature you can see within range, and the sound of a dolorous bell fills the air around it for a moment. The target must succeed on a Wisdom saving throw or take 1d8 necrotic damage. If the target is missing any of its hit points, it instead takes 1d12 necrotic damage.\n\nThe spell\'s damage increases by one die when you reach 5th level (2d8 or 2d12), 11th level (3d8 or 3d12), and 17th level (4d8 or 4d12).', classes: ['cleric', 'warlock', 'wizard'], damageType: 'necrotic', savingThrow: 'wis', tags: ['damage'] },
  { id: 'shillelagh', name: 'Shillelagh', level: 0, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 bonus action', range: 'Self', components: ['V', 'S', 'M'], materialComponent: 'mistletoe, a shamrock leaf, and a club or quarterstaff', duration: '1 minute', concentration: false, ritual: false, description: 'The wood of a club or quarterstaff you are holding is imbued with nature\'s power. For the duration, you can use your spellcasting ability instead of Strength for the attack and damage rolls of melee attacks using that weapon, and the weapon\'s damage die becomes a d8. The weapon also becomes magical, if it isn\'t already. The spell ends if you cast it again or if you let go of the weapon.', classes: ['druid'], tags: ['buff'] },
  { id: 'thunderclap', name: 'Thunderclap', level: 0, school: 'Evocation', sourceBook: 'XGtE', castingTime: '1 action', range: 'Self (5-foot radius)', components: ['S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You create a burst of thunderous sound that can be heard up to 100 feet away. Each creature within range, other than you, must succeed on a Constitution saving throw or take 1d6 thunder damage.\n\nThe spell\'s damage increases by 1d6 when you reach 5th level (2d6), 11th level (3d6), and 17th level (4d6).', classes: ['bard', 'druid', 'sorcerer', 'warlock', 'wizard'], damageType: 'thunder', savingThrow: 'con', tags: ['damage', 'aoe'] },
  { id: 'ray-of-frost', name: 'Ray of Frost', level: 0, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'A frigid beam of blue-white light streaks toward a creature within range. Make a ranged spell attack against the target. On a hit, it takes 1d8 cold damage, and its speed is reduced by 10 feet until the start of your next turn.\n\nThe spell\'s damage increases by 1d8 when you reach 5th level (2d8), 11th level (3d8), and 17th level (4d8).', classes: ['sorcerer', 'wizard'], damageType: 'cold', tags: ['damage', 'control'] },
  { id: 'acid-splash', name: 'Acid Splash', level: 0, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You hurl a bubble of acid. Choose one creature you can see within range, or choose two creatures you can see within range that are within 5 feet of each other. A target must succeed on a Dexterity saving throw or take 1d6 acid damage.\n\nThis spell\'s damage increases by 1d6 when you reach 5th level (2d6), 11th level (3d6), and 17th level (4d6).', classes: ['sorcerer', 'wizard'], damageType: 'acid', savingThrow: 'dex', tags: ['damage'] },
  { id: 'chill-touch', name: 'Chill Touch', level: 0, school: 'Necromancy', sourceBook: 'PHB', castingTime: '1 action', range: '120 feet', components: ['V', 'S'], duration: '1 round', concentration: false, ritual: false, description: 'You create a ghostly, skeletal hand in the space of a creature within range. Make a ranged spell attack against the creature to assail it with the chill of the grave. On a hit, the target takes 1d8 necrotic damage, and it can\'t regain hit points until the start of your next turn. Until then, the hand clings to the target.\n\nIf you hit an undead target, it also has disadvantage on attack rolls against you until the end of your next turn.\n\nThis spell\'s damage increases by 1d8 when you reach 5th level (2d8), 11th level (3d8), and 17th level (4d8).', classes: ['sorcerer', 'warlock', 'wizard'], damageType: 'necrotic', tags: ['damage', 'debuff'] },
  { id: 'spare-the-dying', name: 'Spare the Dying', level: 0, school: 'Necromancy', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You touch a living creature that has 0 hit points. The creature becomes stable. This spell has no effect on undead or constructs.', classes: ['cleric'], tags: ['healing', 'utility'] },
  { id: 'light', name: 'Light', level: 0, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'M'], materialComponent: 'a firefly or phosphorescent moss', duration: '1 hour', concentration: false, ritual: false, description: 'You touch one object that is no larger than 10 feet in any dimension. Until the spell ends, the object sheds bright light in a 20-foot radius and dim light for an additional 20 feet. The light can be colored as you like. Completely covering the object with something opaque blocks the light. The spell ends if you cast it again or dismiss it as an action.\n\nIf you target an object held or worn by a hostile creature, that creature must succeed on a Dexterity saving throw to avoid the spell.', classes: ['bard', 'cleric', 'sorcerer', 'wizard'], tags: ['utility'] },
  { id: 'thaumaturgy', name: 'Thaumaturgy', level: 0, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: '30 feet', components: ['V'], duration: 'Up to 1 minute', concentration: false, ritual: false, description: 'You manifest a minor wonder, a sign of supernatural power, within range. You create one of the following magical effects within range: Your voice booms up to three times as loud as normal for 1 minute. You cause flames to flicker, brighten, dim, or change color for 1 minute. You cause harmless tremors in the ground for 1 minute. You create an instantaneous sound that originates from a point of your choice within range, such as a rumble of thunder, the cry of a raven, or ominous whispers. You instantaneously cause an unlocked door or window to fly open or slam shut. You alter the appearance of your eyes for 1 minute.', classes: ['cleric'], tags: ['utility'] },
  { id: 'druidcraft', name: 'Druidcraft', level: 0, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: '30 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'Whispering to the spirits of nature, you create one of the following effects within range: You create a tiny, harmless sensory effect that predicts what the weather will be at your location for the next 24 hours. You instantly make a flower blossom, a seed pod open, or a leaf bud bloom. You create an instantaneous, harmless sensory effect, such as falling leaves, a puff of wind, the sound of a small animal, or the faint odor of skunk. You light or snuff out a candle, a torch, or a small campfire.', classes: ['druid'], tags: ['utility'] },
  // LEVEL 1
  { id: 'magic-missile', name: 'Magic Missile', level: 1, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '120 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You create three glowing darts of magical force. Each dart hits a creature of your choice that you can see within range. A dart deals 1d4 + 1 force damage to its target. The darts all strike simultaneously, and you can direct them to hit one creature or several.', atHigherLevels: 'When you cast this spell using a spell slot of 2nd level or higher, the spell creates one more dart for each slot level above 1st.', classes: ['sorcerer', 'wizard'], damageType: 'force', tags: ['damage'] },
  { id: 'burning-hands', name: 'Burning Hands', level: 1, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: 'Self (15-foot cone)', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'As you hold your hands with thumbs touching and fingers spread, a thin sheet of flames shoots forth from your outstretched fingertips. Each creature in a 15-foot cone must make a Dexterity saving throw. A creature takes 3d6 fire damage on a failed save, or half as much damage on a successful one.\n\nThe fire ignites any flammable objects in the area that aren\'t being worn or carried.', atHigherLevels: 'When you cast this spell using a spell slot of 2nd level or higher, the damage increases by 1d6 for each slot level above 1st.', classes: ['sorcerer', 'wizard'], damageType: 'fire', savingThrow: 'dex', tags: ['damage', 'aoe'] },
  { id: 'cure-wounds', name: 'Cure Wounds', level: 1, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'A creature you touch regains a number of hit points equal to 1d8 + your spellcasting ability modifier. This spell has no effect on undead or constructs.', atHigherLevels: 'When you cast this spell using a spell slot of 2nd level or higher, the healing increases by 1d8 for each slot level above 1st.', classes: ['bard', 'cleric', 'druid', 'paladin', 'ranger'], tags: ['healing'] },
  { id: 'healing-word', name: 'Healing Word', level: 1, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 bonus action', range: '60 feet', components: ['V'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'A creature of your choice that you can see within range regains hit points equal to 1d4 + your spellcasting ability modifier. This spell has no effect on undead or constructs.', atHigherLevels: 'When you cast this spell using a spell slot of 2nd level or higher, the healing increases by 1d4 for each slot level above 1st.', classes: ['bard', 'cleric', 'druid'], tags: ['healing'] },
  { id: 'shield', name: 'Shield', level: 1, school: 'Abjuration', sourceBook: 'PHB', castingTime: '1 reaction, which you take when you are hit by an attack or targeted by the magic missile spell', range: 'Self', components: ['V', 'S'], duration: '1 round', concentration: false, ritual: false, description: 'An invisible barrier of magical force appears and protects you. Until the start of your next turn, you have a +5 bonus to AC, including against the triggering attack, and you take no damage from magic missile.', classes: ['sorcerer', 'wizard'], tags: ['defense', 'reaction'] },
  { id: 'mage-armor', name: 'Mage Armor', level: 1, school: 'Abjuration', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'a piece of cured leather', duration: '8 hours', concentration: false, ritual: false, description: 'You touch a willing creature who isn\'t wearing armor, and a protective magical force surrounds it until the spell ends. The target\'s base AC becomes 13 + its Dexterity modifier. The spell ends if the target dons armor or if you dismiss the spell as an action.', classes: ['sorcerer', 'wizard'], tags: ['defense', 'buff'] },
  { id: 'sleep', name: 'Sleep', level: 1, school: 'Enchantment', sourceBook: 'PHB', castingTime: '1 action', range: '90 feet', components: ['V', 'S', 'M'], materialComponent: 'a pinch of fine sand, rose petals, or a cricket', duration: '1 minute', concentration: false, ritual: false, description: 'This spell sends creatures into a magical slumber. Roll 5d8; the total is how many hit points of creatures this spell can affect. Creatures within 20 feet of a point you choose within range are affected in ascending order of their current hit points (ignoring unconscious creatures).\n\nStarting with the creature that has the lowest current hit points, each creature affected by this spell falls unconscious until the spell ends, the sleeper takes damage, or someone uses an action to shake or slap the sleeper awake.', atHigherLevels: 'When you cast this spell using a spell slot of 2nd level or higher, roll an additional 2d8 for each slot level above 1st.', classes: ['bard', 'sorcerer', 'wizard'], savingThrow: 'wis', tags: ['control'] },
  { id: 'charm-person', name: 'Charm Person', level: 1, school: 'Enchantment', sourceBook: 'PHB', castingTime: '1 action', range: '30 feet', components: ['V', 'S'], duration: '1 hour', concentration: false, ritual: false, description: 'You attempt to charm a humanoid you can see within range. It must make a Wisdom saving throw, and does so with advantage if you or your companions are fighting it. If it fails the saving throw, it is charmed by you until the spell ends or until you or your companions do anything harmful to it. The charmed creature regards you as a friendly acquaintance. When the spell ends, the creature knows it was charmed by you.', atHigherLevels: 'When you cast this spell using a spell slot of 2nd level or higher, you can target one additional creature for each slot level above 1st.', classes: ['bard', 'druid', 'sorcerer', 'warlock', 'wizard'], savingThrow: 'wis', tags: ['control', 'social'] },
  { id: 'thunderwave', name: 'Thunderwave', level: 1, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: 'Self (15-foot cube)', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'A wave of thunderous force sweeps out from you. Each creature in a 15-foot cube originating from you must make a Constitution saving throw. On a failed save, a creature takes 2d8 thunder damage and is pushed 10 feet away from you. On a successful save, the creature takes half as much damage and isn\'t pushed.\n\nIn addition, unsecured objects that are completely within the area of effect are automatically pushed 10 feet away from you by the spell\'s effect, and the spell emits a thunderous boom audible out to 300 feet.', atHigherLevels: 'When you cast this spell using a spell slot of 2nd level or higher, the damage increases by 1d8 for each slot level above 1st.', classes: ['bard', 'druid', 'sorcerer', 'wizard'], damageType: 'thunder', savingThrow: 'con', tags: ['damage', 'aoe', 'control'] },
  { id: 'bless', name: 'Bless', level: 1, school: 'Enchantment', sourceBook: 'PHB', castingTime: '1 action', range: '30 feet', components: ['V', 'S', 'M'], materialComponent: 'a sprinkling of holy water', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You bless up to three creatures of your choice within range. Whenever a target makes an attack roll or a saving throw before the spell ends, the target can roll a d4 and add the number rolled to the attack roll or saving throw.', atHigherLevels: 'When you cast this spell using a spell slot of 2nd level or higher, you can target one additional creature for each slot level above 1st.', classes: ['cleric', 'paladin'], tags: ['buff'] },
  { id: 'hex', name: 'Hex', level: 1, school: 'Enchantment', sourceBook: 'PHB', castingTime: '1 bonus action', range: '90 feet', components: ['V', 'S', 'M'], materialComponent: 'the petrified eye of a newt', duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: 'You place a curse on a creature that you can see within range. Until the spell ends, you deal an extra 1d6 necrotic damage to the target whenever you hit it with an attack. Also, choose one ability when you cast the spell. The target has disadvantage on ability checks made with the chosen ability.\n\nIf the target drops to 0 hit points before this spell ends, you can use a bonus action on a subsequent turn of yours to curse a new creature.', atHigherLevels: 'When you cast this spell using a spell slot of 3rd or 4th level, you can maintain your concentration on the spell for up to 8 hours. When you use a spell slot of 5th level or higher, you can maintain your concentration on the spell for up to 24 hours.', classes: ['warlock'], damageType: 'necrotic', tags: ['debuff', 'damage'] },
  { id: 'hunters-mark', name: "Hunter's Mark", level: 1, school: 'Divination', sourceBook: 'PHB', castingTime: '1 bonus action', range: '90 feet', components: ['V'], duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: 'You choose a creature you can see within range and mystically mark it as your quarry. Until the spell ends, you deal an extra 1d6 damage to the target whenever you hit it with a weapon attack, and you have advantage on any Wisdom (Perception) or Wisdom (Survival) check you make to find it. If the target drops to 0 hit points before this spell ends, you can use a bonus action on a subsequent turn of yours to mark a new creature.', atHigherLevels: 'When you cast this spell using a spell slot of 3rd or 4th level, you can maintain your concentration on the spell for up to 8 hours. When you use a spell slot of 5th level or higher, you can maintain your concentration on the spell for up to 24 hours.', classes: ['ranger'], tags: ['damage', 'buff'] },
  { id: 'find-familiar', name: 'Find Familiar', level: 1, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 hour', range: '10 feet', components: ['V', 'S', 'M'], materialComponent: '10 gp worth of charcoal, incense, and herbs that must be consumed by fire in a brass brazier', duration: 'Instantaneous', concentration: false, ritual: true, description: 'You gain the service of a familiar, a spirit that takes an animal form you choose: bat, cat, crab, frog (toad), hawk, lizard, octopus, owl, poisonous snake, fish (quipper), rat, raven, sea horse, spider, or weasel. Appearing in an unoccupied space within range, the familiar has the statistics of the chosen form, though it is a celestial, fey, or fiend (your choice) instead of a beast.', classes: ['wizard'], tags: ['utility'] },
  { id: 'divine-smite', name: 'Divine Smite', level: 1, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 bonus action', range: 'Self', components: ['V'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'The first time you hit with a melee weapon attack during this spell\'s duration, your weapon flares with white-hot intensity, and the attack deals an extra 2d8 radiant damage to the target. The spell then ends. If you hit a fiend or an undead, the attack deals an extra 1d8 radiant damage.', atHigherLevels: 'When you cast this spell using a spell slot of 2nd level or higher, the extra damage increases by 1d8 for each slot level above 1st (maximum 5d8). The damage increases by another 1d8 if the target is an undead or a fiend (maximum 6d8).', classes: ['paladin'], damageType: 'radiant', tags: ['damage'] },
  { id: 'guiding-bolt', name: 'Guiding Bolt', level: 1, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '120 feet', components: ['V', 'S'], duration: '1 round', concentration: false, ritual: false, description: 'A flash of light streaks toward a creature of your choice within range. Make a ranged spell attack against the target. On a hit, the target takes 4d6 radiant damage, and the next attack roll made against this target before the end of your next turn has advantage, thanks to the mystical dim light glittering on the target until then.', atHigherLevels: 'When you cast this spell using a spell slot of 2nd level or higher, the damage increases by 1d6 for each slot level above 1st.', classes: ['cleric'], damageType: 'radiant', tags: ['damage', 'buff'] },
  { id: 'inflict-wounds', name: 'Inflict Wounds', level: 1, school: 'Necromancy', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'Make a melee spell attack against a creature you can reach. On a hit, the target takes 3d10 necrotic damage.', atHigherLevels: 'When you cast this spell using a spell slot of 2nd level or higher, the damage increases by 1d10 for each slot level above 1st.', classes: ['cleric'], damageType: 'necrotic', tags: ['damage'] },
  { id: 'detect-magic', name: 'Detect Magic', level: 1, school: 'Divination', sourceBook: 'PHB', castingTime: '1 action', range: 'Self', components: ['V', 'S'], duration: 'Concentration, up to 10 minutes', concentration: true, ritual: true, description: 'For the duration, you sense the presence of magic within 30 feet of you. If you sense magic in this way, you can use your action to see a faint aura around any visible creature or object in the area that bears magic, and you learn its school of magic, if any.\n\nThe spell can penetrate most barriers, but it is blocked by 1 foot of stone, 1 inch of common metal, a thin sheet of lead, or 3 feet of wood or dirt.', classes: ['bard', 'cleric', 'druid', 'paladin', 'ranger', 'sorcerer', 'wizard'], tags: ['utility', 'detection'] },
  { id: 'identify', name: 'Identify', level: 1, school: 'Divination', sourceBook: 'PHB', castingTime: '1 minute', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'a pearl worth at least 100 gp and an owl feather', duration: 'Instantaneous', concentration: false, ritual: true, description: 'You choose one object that you must touch throughout the casting of the spell. If it is a magic item or some other magic-imbued object, you learn its properties and how to use them, whether it requires attunement to use, and how many charges it has, if any. You learn whether any spells are affecting the item and what they are. If the item was created by a spell, you learn which spell created it.\n\nIf you instead touch a creature throughout the casting, you learn what spells, if any, are currently affecting it.', classes: ['bard', 'wizard'], tags: ['utility', 'detection'] },
  { id: 'sanctuary', name: 'Sanctuary', level: 1, school: 'Abjuration', sourceBook: 'PHB', castingTime: '1 bonus action', range: '30 feet', components: ['V', 'S', 'M'], materialComponent: 'a small silver mirror', duration: '1 minute', concentration: false, ritual: false, description: 'You ward a creature within range against attack. Until the spell ends, any creature who targets the warded creature with an attack or a harmful spell must first make a Wisdom saving throw. On a failed save, the creature must choose a new target or lose the attack or spell. This spell doesn\'t protect the warded creature from area effects, such as the explosion of a fireball.\n\nIf the warded creature makes an attack, casts a spell that affects an enemy, or deals damage to another creature, this spell ends.', classes: ['cleric'], savingThrow: 'wis', tags: ['defense', 'utility'] },
  // LEVEL 2
  { id: 'misty-step', name: 'Misty Step', level: 2, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 bonus action', range: 'Self', components: ['V'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'Briefly surrounded by silvery mist, you teleport up to 30 feet to an unoccupied space that you can see.', classes: ['sorcerer', 'warlock', 'wizard'], tags: ['movement', 'utility'] },
  { id: 'scorching-ray', name: 'Scorching Ray', level: 2, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '120 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You create three rays of fire and hurl them at targets within range. You can hurl them at one target or several. Make a ranged spell attack for each ray. On a hit, the target takes 2d6 fire damage.', atHigherLevels: 'When you cast this spell using a spell slot of 3rd level or higher, you create one additional ray for each slot level above 2nd.', classes: ['sorcerer', 'wizard'], damageType: 'fire', tags: ['damage'] },
  { id: 'hold-person', name: 'Hold Person', level: 2, school: 'Enchantment', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S', 'M'], materialComponent: 'a small, straight piece of iron', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'Choose a humanoid that you can see within range. The target must succeed on a Wisdom saving throw or be paralyzed for the duration. At the end of each of its turns, the target can make another Wisdom saving throw. On a success, the spell ends on the target.', atHigherLevels: 'When you cast this spell using a spell slot of 3rd level or higher, you can target one additional humanoid for each slot level above 2nd.', classes: ['bard', 'cleric', 'druid', 'sorcerer', 'warlock', 'wizard'], savingThrow: 'wis', tags: ['control'] },
  { id: 'invisibility', name: 'Invisibility', level: 2, school: 'Illusion', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'an eyelash encased in gum arabic', duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: 'A creature you touch becomes invisible until the spell ends. Anything the target is wearing or carrying is invisible as long as it is on the target\'s person. The spell ends for a target that attacks or casts a spell.', atHigherLevels: 'When you cast this spell using a spell slot of 3rd level or higher, you can target one additional creature for each slot level above 2nd.', classes: ['bard', 'sorcerer', 'warlock', 'wizard'], tags: ['stealth', 'utility'] },
  { id: 'spiritual-weapon', name: 'Spiritual Weapon', level: 2, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 bonus action', range: '60 feet', components: ['V', 'S'], duration: '1 minute', concentration: false, ritual: false, description: 'You create a floating, spectral weapon within range that lasts for the duration or until you cast this spell again. When you cast the spell, you can make a melee spell attack against a creature within 5 feet of the weapon. On a hit, the target takes force damage equal to 1d8 + your spellcasting ability modifier.\n\nAs a bonus action on your turn, you can move the weapon up to 20 feet and repeat the attack against a creature within 5 feet of it.', atHigherLevels: 'When you cast this spell using a spell slot of 3rd level or higher, the damage increases by 1d8 for every two slot levels above 2nd.', classes: ['cleric'], damageType: 'force', tags: ['damage', 'bonus-action'] },
  { id: 'shatter', name: 'Shatter', level: 2, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S', 'M'], materialComponent: 'a chip of mica', duration: 'Instantaneous', concentration: false, ritual: false, description: 'A sudden loud ringing noise, painfully intense, erupts from a point of your choice within range. Each creature in a 10-foot-radius sphere centered on that point must make a Constitution saving throw. A creature takes 3d8 thunder damage on a failed save, or half as much damage on a successful one. A creature made of inorganic material such as stone, crystal, or metal has disadvantage on this saving throw.\n\nA nonmagical object that isn\'t being worn or carried also takes the damage if it\'s in the spell\'s area.', atHigherLevels: 'When you cast this spell using a spell slot of 3rd level or higher, the damage increases by 1d8 for each slot level above 2nd.', classes: ['bard', 'sorcerer', 'warlock', 'wizard'], damageType: 'thunder', savingThrow: 'con', tags: ['damage', 'aoe'] },
  { id: 'lesser-restoration', name: 'Lesser Restoration', level: 2, school: 'Abjuration', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You touch a creature and can end either one disease or one condition afflicting it. The condition can be blinded, deafened, paralyzed, or poisoned.', classes: ['bard', 'cleric', 'druid', 'paladin', 'ranger'], tags: ['healing', 'utility'] },
  { id: 'prayer-of-healing', name: 'Prayer of Healing', level: 2, school: 'Evocation', sourceBook: 'PHB', castingTime: '10 minutes', range: '30 feet', components: ['V'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'Up to six creatures of your choice that you can see within range each regain hit points equal to 2d8 + your spellcasting ability modifier. This spell has no effect on undead or constructs.', atHigherLevels: 'When you cast this spell using a spell slot of 3rd level or higher, the healing increases by 1d8 for each slot level above 2nd.', classes: ['cleric'], tags: ['healing', 'aoe'] },
  { id: 'mirror-image', name: 'Mirror Image', level: 2, school: 'Illusion', sourceBook: 'PHB', castingTime: '1 action', range: 'Self', components: ['V', 'S'], duration: '1 minute', concentration: false, ritual: false, description: 'Three illusory duplicates of yourself appear in your space. Until the spell ends, the duplicates move with you and mimic your actions, shifting position so it\'s impossible to track which image is real. You can use your action to dismiss the illusory duplicates.\n\nEach time a creature targets you with an attack during the spell\'s duration, roll a d20 to determine whether the attack instead targets one of your duplicates.', classes: ['sorcerer', 'warlock', 'wizard'], tags: ['defense', 'illusion'] },
  { id: 'blur', name: 'Blur', level: 2, school: 'Illusion', sourceBook: 'PHB', castingTime: '1 action', range: 'Self', components: ['V'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'Your body becomes blurred, shifting and wavering to all who can see you. For the duration, any creature has disadvantage on attack rolls against you. An attacker is immune to this effect if it doesn\'t rely on sight, as with blindsight, or can see through illusions, as with truesight.', classes: ['sorcerer', 'wizard'], tags: ['defense', 'illusion'] },
  { id: 'moonbeam', name: 'Moonbeam', level: 2, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '120 feet', components: ['V', 'S', 'M'], materialComponent: 'several seeds of any moonseed plant and a piece of opalescent feldspar', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'A silvery beam of pale light shines down in a 5-foot-radius, 40-foot-high cylinder centered on a point within range. Until the spell ends, dim light fills the cylinder.\n\nWhen a creature enters the spell\'s area for the first time on a turn or starts its turn there, it is engulfed in ghostly flames that cause searing pain, and it must make a Constitution saving throw. It takes 2d10 radiant damage on a failed save, or half as much damage on a successful one.', atHigherLevels: 'When you cast this spell using a spell slot of 3rd level or higher, the damage increases by 1d10 for each slot level above 2nd.', classes: ['druid'], damageType: 'radiant', savingThrow: 'con', tags: ['damage', 'aoe'] },
  // LEVEL 3
  { id: 'fireball', name: 'Fireball', level: 3, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '150 feet', components: ['V', 'S', 'M'], materialComponent: 'a tiny ball of bat guano and sulfur', duration: 'Instantaneous', concentration: false, ritual: false, description: 'A bright streak flashes from your pointing finger to a point you choose within range and then blossoms with a low roar into an explosion of flame. Each creature in a 20-foot-radius sphere centered on that point must make a Dexterity saving throw. A target takes 8d6 fire damage on a failed save, or half as much damage on a successful one.\n\nThe fire spreads around corners. It ignites flammable objects in the area that aren\'t being worn or carried.', atHigherLevels: 'When you cast this spell using a spell slot of 4th level or higher, the damage increases by 1d6 for each slot level above 3rd.', classes: ['sorcerer', 'wizard'], damageType: 'fire', savingThrow: 'dex', tags: ['damage', 'aoe'] },
  { id: 'lightning-bolt', name: 'Lightning Bolt', level: 3, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: 'Self (100-foot line)', components: ['V', 'S', 'M'], materialComponent: 'a bit of fur and a rod of amber, crystal, or glass', duration: 'Instantaneous', concentration: false, ritual: false, description: 'A stroke of lightning forming a line 100 feet long and 5 feet wide blasts out from you in a direction you choose. Each creature in the line must make a Dexterity saving throw. A creature takes 8d6 lightning damage on a failed save, or half as much damage on a successful one.\n\nThe lightning ignites flammable objects in the area that aren\'t being worn or carried.', atHigherLevels: 'When you cast this spell using a spell slot of 4th level or higher, the damage increases by 1d6 for each slot level above 3rd.', classes: ['sorcerer', 'wizard'], damageType: 'lightning', savingThrow: 'dex', tags: ['damage', 'aoe'] },
  { id: 'counterspell', name: 'Counterspell', level: 3, school: 'Abjuration', sourceBook: 'PHB', castingTime: '1 reaction, which you take when you see a creature within 60 feet of you casting a spell', range: '60 feet', components: ['S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You attempt to interrupt a creature in the process of casting a spell. If the creature is casting a spell of 3rd level or lower, its spell fails and has no effect. If it is casting a spell of 4th level or higher, make an ability check using your spellcasting ability. The DC equals 10 + the spell\'s level. On a success, the creature\'s spell fails and has no effect.', atHigherLevels: 'When you cast this spell using a spell slot of 4th level or higher, the interrupted spell has no effect if its level is less than or equal to the level of the spell slot you used.', classes: ['sorcerer', 'warlock', 'wizard'], tags: ['reaction', 'defense', 'counter'] },
  { id: 'dispel-magic', name: 'Dispel Magic', level: 3, school: 'Abjuration', sourceBook: 'PHB', castingTime: '1 action', range: '120 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'Choose one creature, object, or magical effect within range. Any spell of 3rd level or lower on the target ends. For each spell of 4th level or higher on the target, make an ability check using your spellcasting ability. The DC equals 10 + the spell\'s level. On a successful check, the spell ends.', atHigherLevels: 'When you cast this spell using a spell slot of 4th level or higher, you automatically end the effects of a spell on the target if the spell\'s level is equal to or less than the level of the spell slot you used.', classes: ['bard', 'cleric', 'druid', 'paladin', 'sorcerer', 'warlock', 'wizard'], tags: ['utility', 'counter'] },
  { id: 'fly', name: 'Fly', level: 3, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'a wing feather from any bird', duration: 'Concentration, up to 10 minutes', concentration: true, ritual: false, description: 'You touch a willing creature. The target gains a flying speed of 60 feet for the duration. When the spell ends, the target falls if it is still aloft, unless it can stop the fall.', atHigherLevels: 'When you cast this spell using a spell slot of 4th level or higher, you can target one additional creature for each slot level above 3rd.', classes: ['sorcerer', 'warlock', 'wizard'], tags: ['movement', 'utility'] },
  { id: 'haste', name: 'Haste', level: 3, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: '30 feet', components: ['V', 'S', 'M'], materialComponent: 'a shaving of licorice root', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'Choose a willing creature that you can see within range. Until the spell ends, the target\'s speed is doubled, it gains a +2 bonus to AC, it has advantage on Dexterity saving throws, and it gains an additional action on each of its turns. That action can be used only to take the Attack (one weapon attack only), Dash, Disengage, Hide, or Use an Object action.\n\nWhen the spell ends, the target can\'t move or take actions until after its next turn, as a wave of lethargy sweeps over it.', classes: ['sorcerer', 'wizard'], tags: ['buff', 'control'] },
  { id: 'spirit-guardians', name: 'Spirit Guardians', level: 3, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 action', range: 'Self (15-foot radius)', components: ['V', 'S', 'M'], materialComponent: 'a holy symbol', duration: 'Concentration, up to 10 minutes', concentration: true, ritual: false, description: 'You call forth spirits to protect you. They flit around you to a distance of 15 feet for the duration. If you are good or neutral, their spectral form appears angelic or fey (your choice). If you are evil, they appear fiendish.\n\nWhen you cast this spell, you can designate any number of creatures you can see to be unaffected by it. An affected creature\'s speed is halved in the area, and when the creature enters the area for the first time on a turn or starts its turn there, it must make a Wisdom saving throw. On a failed save, the creature takes 3d8 radiant damage (if you are good or neutral) or 3d8 necrotic damage (if you are evil). On a successful save, the creature takes half as much damage.', atHigherLevels: 'When you cast this spell using a spell slot of 4th level or higher, the damage increases by 1d8 for each slot level above 3rd.', classes: ['cleric'], damageType: 'radiant', savingThrow: 'wis', tags: ['damage', 'aoe', 'control'] },
  { id: 'revivify', name: 'Revivify', level: 3, school: 'Necromancy', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'diamonds worth 300 gp, which the spell consumes', duration: 'Instantaneous', concentration: false, ritual: false, description: 'You touch a creature that has died within the last minute. That creature returns to life with 1 hit point. This spell can\'t return to life a creature that has died of old age, nor can it restore any missing body parts.', classes: ['cleric', 'druid', 'paladin'], tags: ['healing', 'utility'] },
  { id: 'mass-healing-word', name: 'Mass Healing Word', level: 3, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 bonus action', range: '60 feet', components: ['V'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'As you call out words of restoration, up to six creatures of your choice that you can see within range regain hit points equal to 1d4 + your spellcasting ability modifier. This spell has no effect on undead or constructs.', atHigherLevels: 'When you cast this spell using a spell slot of 4th level or higher, the healing increases by 1d4 for each slot level above 3rd.', classes: ['cleric'], tags: ['healing', 'aoe'] },
  // LEVEL 4
  { id: 'banishment', name: 'Banishment', level: 4, school: 'Abjuration', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S', 'M'], materialComponent: 'an item distasteful to the target', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You attempt to send one creature that you can see within range to another place of existence. The target must succeed on a Charisma saving throw or be banished.\n\nIf the target is native to the plane of existence you\'re on, you banish the target to a harmless demiplane. While there, the target is incapacitated. The target remains there until the spell ends, at which point the target reappears in the space it left or in the nearest unoccupied space if that space is occupied.', atHigherLevels: 'When you cast this spell using a spell slot of 5th level or higher, you can target one additional creature for each slot level above 4th.', classes: ['cleric', 'paladin', 'sorcerer', 'warlock', 'wizard'], savingThrow: 'cha', tags: ['control'] },
  { id: 'polymorph', name: 'Polymorph', level: 4, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S', 'M'], materialComponent: 'a caterpillar cocoon', duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: 'This spell transforms a creature that you can see within range into a new form. An unwilling creature must make a Wisdom saving throw to avoid the effect. A shapechanger automatically succeeds on this saving throw.\n\nThe transformation lasts for the duration, or until the target drops to 0 hit points or dies. The new form can be any beast whose challenge rating is equal to or less than the target\'s (or the target\'s level, if it doesn\'t have a challenge rating). The target\'s game statistics, including mental ability scores, are replaced by the statistics of the chosen beast.', classes: ['bard', 'druid', 'sorcerer', 'wizard'], savingThrow: 'wis', tags: ['control', 'utility'] },
  { id: 'dimension-door', name: 'Dimension Door', level: 4, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 action', range: '500 feet', components: ['V'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You teleport yourself from your current location to any other spot within range. You arrive at exactly the spot desired. It can be a place you can see, one you can visualize, or one you can describe by stating distance and direction, such as "200 feet straight downward" or "upward to the northwest at a 45-degree angle, 300 feet."\n\nYou can bring along objects as long as their weight doesn\'t exceed what you can carry. You can also bring one willing creature of your size or smaller who is carrying gear up to its carrying capacity.', classes: ['bard', 'sorcerer', 'warlock', 'wizard'], tags: ['movement', 'utility'] },
  { id: 'greater-invisibility', name: 'Greater Invisibility', level: 4, school: 'Illusion', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You or a creature you touch becomes invisible until the spell ends. Anything the target is wearing or carrying is invisible as long as it is on the target\'s person.', classes: ['bard', 'sorcerer', 'wizard'], tags: ['stealth', 'buff'] },
  // LEVEL 5
  { id: 'hold-monster', name: 'Hold Monster', level: 5, school: 'Enchantment', sourceBook: 'PHB', castingTime: '1 action', range: '90 feet', components: ['V', 'S', 'M'], materialComponent: 'a small, straight piece of iron', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'Choose a creature that you can see within range. The target must succeed on a Wisdom saving throw or be paralyzed for the duration. This spell has no effect on undead. At the end of each of its turns, the target can make another Wisdom saving throw. On a success, the spell ends on the target.', atHigherLevels: 'When you cast this spell using a spell slot of 6th level or higher, you can target one additional creature for each slot level above 5th.', classes: ['bard', 'sorcerer', 'warlock', 'wizard'], savingThrow: 'wis', tags: ['control'] },
  { id: 'cone-of-cold', name: 'Cone of Cold', level: 5, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: 'Self (60-foot cone)', components: ['V', 'S', 'M'], materialComponent: 'a small crystal or glass cone', duration: 'Instantaneous', concentration: false, ritual: false, description: 'A blast of cold air erupts from your hands. Each creature in a 60-foot cone must make a Constitution saving throw. A creature takes 8d8 cold damage on a failed save, or half as much damage on a successful one.\n\nA creature killed by this spell becomes a frozen statue until it thaws.', atHigherLevels: 'When you cast this spell using a spell slot of 6th level or higher, the damage increases by 1d8 for each slot level above 5th.', classes: ['sorcerer', 'wizard'], damageType: 'cold', savingThrow: 'con', tags: ['damage', 'aoe'] },
  { id: 'mass-cure-wounds', name: 'Mass Cure Wounds', level: 5, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'A wave of healing energy washes out from a point of your choice within range. Choose up to six creatures in a 30-foot-radius sphere centered on that point. Each target regains hit points equal to 3d8 + your spellcasting ability modifier. This spell has no effect on undead or constructs.', atHigherLevels: 'When you cast this spell using a spell slot of 6th level or higher, the healing increases by 1d8 for each slot level above 5th.', classes: ['bard', 'cleric', 'druid'], tags: ['healing', 'aoe'] },
  { id: 'wall-of-force', name: 'Wall of Force', level: 5, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '120 feet', components: ['V', 'S', 'M'], materialComponent: 'a pinch of powder made by crushing a clear gemstone', duration: 'Concentration, up to 10 minutes', concentration: true, ritual: false, description: 'An invisible wall of force springs into existence at a point you choose within range. The wall appears in any orientation you choose, as a horizontal or vertical barrier or at an angle. It can be free floating or resting on a solid surface. You can form it into a hemispherical dome or a sphere with a radius of up to 10 feet, or you can shape a flat surface made up of ten 10-by-10-foot panels.', classes: ['wizard'], tags: ['control', 'utility'] },
  { id: 'flame-strike', name: 'Flame Strike', level: 5, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S', 'M'], materialComponent: 'pinch of sulfur', duration: 'Instantaneous', concentration: false, ritual: false, description: 'A vertical column of divine fire roars down from the heavens in a location you specify. Each creature in a 10-foot-radius, 40-foot-high cylinder centered on a point within range must make a Dexterity saving throw. A creature takes 4d6 fire damage and 4d6 radiant damage on a failed save, or half as much damage on a successful one.', atHigherLevels: 'When you cast this spell using a spell slot of 6th level or higher, the fire damage or the radiant damage (your choice) increases by 1d6 for each slot level above 5th.', classes: ['cleric'], damageType: 'fire', savingThrow: 'dex', tags: ['damage', 'aoe'] },
  // LEVEL 6
  { id: 'chain-lightning', name: 'Chain Lightning', level: 6, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '150 feet', components: ['V', 'S', 'M'], materialComponent: 'a bit of fur; a piece of amber, glass, or a crystal rod; and three silver pins', duration: 'Instantaneous', concentration: false, ritual: false, description: 'You create a bolt of lightning that arcs toward a target of your choice that you can see within range. Three bolts then leap from that target to as many as three other targets, each of which must be within 30 feet of the first target. A target can be a creature or an object and can be targeted by only one of the bolts.\n\nA target must make a Dexterity saving throw. The target takes 10d8 lightning damage on a failed save, or half as much damage on a successful one.', atHigherLevels: 'When you cast this spell using a spell slot of 7th level or higher, one additional bolt leaps from the first target to another target for each slot level above 6th.', classes: ['sorcerer', 'wizard'], damageType: 'lightning', savingThrow: 'dex', tags: ['damage', 'aoe'] },
  { id: 'true-seeing', name: 'True Seeing', level: 6, school: 'Divination', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'an ointment for the eyes that costs 25 gp; is made from mushroom powder, saffron, and fat; and is consumed by the spell', duration: '1 hour', concentration: false, ritual: false, description: 'You give the willing creature you touch the ability to see things as they actually are. For the duration, the creature has truesight, notices secret doors hidden by magic, and can see into the Ethereal Plane, all out to a range of 120 feet.', classes: ['bard', 'cleric', 'sorcerer', 'warlock', 'wizard'], tags: ['utility', 'detection'] },
  // LEVEL 7
  { id: 'finger-of-death', name: 'Finger of Death', level: 7, school: 'Necromancy', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You send negative energy coursing through a creature that you can see within range, causing it searing pain. The target must make a Constitution saving throw. It takes 7d8 + 30 necrotic damage on a failed save, or half as much damage on a successful one.\n\nA humanoid killed by this spell rises at the start of your next turn as a zombie that is permanently under your command, following your verbal orders to the best of its ability.', classes: ['sorcerer', 'warlock', 'wizard'], damageType: 'necrotic', savingThrow: 'con', tags: ['damage'] },
  { id: 'teleport', name: 'Teleport', level: 7, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 action', range: '10 feet', components: ['V'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'This spell instantly transports you and up to eight willing creatures of your choice that you can see within range, or a single object that you can see within range, to a destination you select. If you target an object, it must be able to fit entirely inside a 10-foot cube, and it can\'t be held or carried by an unwilling creature.', classes: ['bard', 'sorcerer', 'wizard'], tags: ['movement', 'utility'] },
  // LEVEL 8
  { id: 'power-word-stun', name: 'Power Word Stun', level: 8, school: 'Enchantment', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V'], duration: 'Until ended', concentration: false, ritual: false, description: 'You speak a word of power that overwhelms the mind of one creature you can see within range, leaving it dumbfounded. If the target has 150 hit points or fewer, it is stunned. Otherwise, the spell has no effect.\n\nThe stunned target must make a Constitution saving throw at the end of each of its turns. On a successful save, the stunning effect ends.', classes: ['sorcerer', 'warlock', 'wizard'], savingThrow: 'con', tags: ['control'] },
  // LEVEL 9
  { id: 'wish', name: 'Wish', level: 9, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 action', range: 'Self', components: ['V'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'Wish is the mightiest spell a mortal creature can cast. By simply speaking aloud, you can alter the very foundations of reality in accord with your desires.\n\nThe basic use of this spell is to duplicate any other spell of 8th level or lower. You don\'t need to meet any requirements in that spell, including costly components. The spell simply takes effect. Alternatively, you can create one of the following effects of your choice: You create one object of up to 25,000 gp in value that isn\'t a magic item. The object can be no more than 300 feet in any dimension, and it appears in an unoccupied space you can see on the ground. You allow up to twenty creatures that you can see to regain all hit points, and you end all effects on them described in the greater restoration spell. You grant up to ten creatures that you can see immunity to a single spell or other magical effect for 8 hours. You undo a single recent event by forcing a reroll of any roll made within the last round (including your last turn). Reality reshapes itself to accommodate the new result.', classes: ['sorcerer', 'wizard'], tags: ['utility'] },
  { id: 'power-word-kill', name: 'Power Word Kill', level: 9, school: 'Enchantment', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You utter a word of power that can compel one creature you can see within range to die instantly. If the creature you choose has 100 hit points or fewer, it dies. Otherwise, the spell has no effect.', classes: ['sorcerer', 'warlock', 'wizard'], tags: ['damage'] },
  { id: 'meteor-swarm', name: 'Meteor Swarm', level: 9, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '1 mile', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'Blazing orbs of fire plummet to the ground at four different points you can see within range. Each creature in a 40-foot-radius sphere centered on each point you choose must make a Dexterity saving throw. The sphere spreads around corners. A creature takes 20d6 fire damage and 20d6 bludgeoning damage on a failed save, or half as much damage on a successful one. A creature in the area of more than one fiery burst is affected only once. The spell damages objects in the area and ignites flammable objects that aren\'t being worn or carried.', classes: ['sorcerer', 'wizard'], damageType: 'fire', savingThrow: 'dex', tags: ['damage', 'aoe'] },

  // ── ADDITIONAL CANTRIPS ──────────────────────────────────────────────────
  { id: 'message', name: 'Message', level: 0, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: '120 feet', components: ['V', 'S', 'M'], materialComponent: 'a short piece of copper wire', duration: '1 round', concentration: false, ritual: false, description: 'You point your finger toward a creature within range and whisper a message. The target (and only the target) hears the message and can reply in a whisper that only you can hear.\n\nYou can cast this spell through solid objects if you are familiar with the target and know it is beyond the barrier. Magical silence, 1 foot of stone, 1 inch of common metal, a thin sheet of lead, or 3 feet of wood blocks the spell. The spell doesn\'t have to follow a straight line and can travel freely around corners or through openings.', classes: ['bard', 'sorcerer', 'wizard'], tags: ['utility', 'communication'] },
  { id: 'dancing-lights', name: 'Dancing Lights', level: 0, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '120 feet', components: ['V', 'S', 'M'], materialComponent: 'a bit of phosphorus or wychwood, or a glowworm', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You create up to four torch-sized lights within range, making them appear as torches, lanterns, or glowing orbs that hover in the air for the duration. You can also combine the four lights into one glowing vaguely humanoid form of Medium size. Whichever form you choose, each light sheds dim light in a 10-foot radius.\n\nAs a bonus action on your turn, you can move the lights up to 60 feet to a new spot within range. A light must be within 20 feet of another light created by this spell, and a light winks out if it exceeds the spell\'s range.', classes: ['bard', 'sorcerer', 'wizard'], tags: ['utility', 'light'] },
  { id: 'shocking-grasp', name: 'Shocking Grasp', level: 0, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'Lightning springs from your hand to deliver a shock to a creature you try to touch. Make a melee spell attack against the target. You have advantage on the attack roll if the target is wearing armor made of metal. On a hit, the target takes 1d8 lightning damage, and it can\'t take reactions until the start of its next turn.\n\nThe spell\'s damage increases by 1d8 when you reach 5th level (2d8), 11th level (3d8), and 17th level (4d8).', classes: ['sorcerer', 'wizard'], damageType: 'lightning', tags: ['damage', 'melee'] },
  { id: 'poison-spray', name: 'Poison Spray', level: 0, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 action', range: '10 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You extend your hand toward a creature you can see within range and project a puff of noxious gas from your palm. The creature must succeed on a Constitution saving throw or take 1d12 poison damage.\n\nThis spell\'s damage increases by 1d12 when you reach 5th level (2d12), 11th level (3d12), and 17th level (4d12).', classes: ['druid', 'sorcerer', 'warlock', 'wizard'], damageType: 'poison', savingThrow: 'con', tags: ['damage'] },
  { id: 'true-strike', name: 'True Strike', level: 0, school: 'Divination', sourceBook: 'PHB', castingTime: '1 action', range: '30 feet', components: ['S'], duration: 'Concentration, up to 1 round', concentration: true, ritual: false, description: 'You extend your hand and point a finger at a target in range. Your magic grants you a brief insight into the target\'s defenses. On your next turn, you gain advantage on your first attack roll against the target, provided that this spell hasn\'t ended.', classes: ['bard', 'sorcerer', 'warlock', 'wizard'], tags: ['utility'] },
  { id: 'resistance', name: 'Resistance', level: 0, school: 'Abjuration', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'a miniature cloak', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You touch one willing creature. Once before the spell ends, the target can roll a d4 and add the number rolled to one saving throw of its choice. It can roll the die before or after making the saving throw. The spell then ends.', classes: ['cleric', 'druid'], tags: ['buff'] },
  { id: 'mending', name: 'Mending', level: 0, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 minute', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'two lodestones', duration: 'Instantaneous', concentration: false, ritual: false, description: 'This spell repairs a single break or tear in an object you touch, such as a broken chain link, two halves of a broken key, a torn cloak, or a leaking wineskin. As long as the break or tear is no larger than 1 foot in any dimension, you mend it, leaving no trace of the former damage.\n\nThis spell can physically repair a magic item or construct, but the spell can\'t restore magic to such an object.', classes: ['bard', 'cleric', 'druid', 'sorcerer', 'wizard'], tags: ['utility'] },
  { id: 'blade-ward', name: 'Blade Ward', level: 0, school: 'Abjuration', sourceBook: 'PHB', castingTime: '1 action', range: 'Self', components: ['V', 'S'], duration: '1 round', concentration: false, ritual: false, description: 'You extend your hand and trace a sigil of warding in the air. Until the end of your next turn, you have resistance against bludgeoning, piercing, and slashing damage dealt by weapon attacks.', classes: ['bard', 'sorcerer', 'warlock', 'wizard'], tags: ['defense'] },
  { id: 'friends', name: 'Friends', level: 0, school: 'Enchantment', sourceBook: 'PHB', castingTime: '1 action', range: 'Self', components: ['S', 'M'], materialComponent: 'a small amount of makeup applied to the face as this spell is cast', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'For the duration, you have advantage on all Charisma checks directed at one creature of your choice that isn\'t hostile toward you. When the spell ends, the creature realizes that you used magic to influence its mood and becomes hostile toward you. A creature prone to violence might attack you. Another creature might seek retribution in other ways (at the DM\'s discretion), depending on the nature of your interaction with it.', classes: ['bard', 'sorcerer', 'warlock', 'wizard'], tags: ['social', 'enchantment'] },
  { id: 'produce-flame', name: 'Produce Flame', level: 0, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 action', range: 'Self', components: ['V', 'S'], duration: '10 minutes', concentration: false, ritual: false, description: 'A flickering flame appears in your hand. The flame remains there for the duration and harms neither you nor your equipment. The flame sheds bright light in a 10-foot radius and dim light for an additional 10 feet. The spell ends if you dismiss it as an action or if you cast it again.\n\nYou can also attack with the flame, although doing so ends the spell. When you cast this spell, or as an action on a later turn, you can hurl the flame at a creature within 30 feet of you. Make a ranged spell attack. On a hit, the target takes 1d8 fire damage.\n\nThis spell\'s damage increases by 1d8 when you reach 5th level (2d8), 11th level (3d8), and 17th level (4d8).', classes: ['druid'], damageType: 'fire', tags: ['damage', 'light'] },
  { id: 'infestation', name: 'Infestation', level: 0, school: 'Conjuration', sourceBook: 'XGtE', castingTime: '1 action', range: '30 feet', components: ['V', 'S', 'M'], materialComponent: 'a living flea', duration: 'Instantaneous', concentration: false, ritual: false, description: 'You cause a cloud of mites, fleas, and other parasites to appear momentarily on one creature you can see within range. The target must succeed on a Constitution saving throw, or it takes 1d6 poison damage and moves 5 feet in a random direction if it can move and its speed is at least 5 feet. Roll a d4 for the direction: 1, north; 2, south; 3, east; or 4, west. This movement doesn\'t provoke opportunity attacks, and if the direction rolled is blocked, the target doesn\'t move.\n\nThe spell\'s damage increases by 1d6 when you reach 5th level (2d6), 11th level (3d6), and 17th level (4d6).', classes: ['druid', 'sorcerer', 'warlock', 'wizard'], damageType: 'poison', savingThrow: 'con', tags: ['damage'] },
  { id: 'frostbite', name: 'Frostbite', level: 0, school: 'Evocation', sourceBook: 'XGtE', castingTime: '1 action', range: '60 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You cause numbing frost to form on one creature that you can see within range. The target must make a Constitution saving throw. On a failed save, the target takes 1d6 cold damage, and it has disadvantage on the next weapon attack roll it makes before the end of its next turn.\n\nThe spell\'s damage increases by 1d6 when you reach 5th level (2d6), 11th level (3d6), and 17th level (4d6).', classes: ['druid', 'sorcerer', 'warlock', 'wizard'], damageType: 'cold', savingThrow: 'con', tags: ['damage'] },
  { id: 'toll-the-dead-2', name: 'Word of Radiance', level: 0, school: 'Evocation', sourceBook: 'XGtE', castingTime: '1 action', range: '5 feet', components: ['V', 'M'], materialComponent: 'a holy symbol', duration: 'Instantaneous', concentration: false, ritual: false, description: 'You utter a divine word, and burning radiance erupts from you. Each creature of your choice that you can see within range must succeed on a Constitution saving throw or take 1d6 radiant damage.\n\nThe spell\'s damage increases by 1d6 when you reach 5th level (2d6), 11th level (3d6), and 17th level (4d6).', classes: ['cleric'], damageType: 'radiant', savingThrow: 'con', tags: ['damage', 'aoe'] },

  // ── ADDITIONAL LEVEL 1 SPELLS ────────────────────────────────────────────
  { id: 'armor-of-agathys', name: 'Armor of Agathys', level: 1, school: 'Abjuration', sourceBook: 'PHB', castingTime: '1 action', range: 'Self', components: ['V', 'S', 'M'], materialComponent: 'a cup of water', duration: '1 hour', concentration: false, ritual: false, description: 'A protective magical force surrounds you, manifesting as a spectral frost that covers you and your gear. You gain 5 temporary hit points for the duration. If a creature hits you with a melee attack while you have these hit points, the creature takes 5 cold damage.\n\nAt Higher Levels: When you cast this spell using a spell slot of 2nd level or higher, both the temporary hit points and the cold damage increase by 5 for each slot level above 1st.', atHigherLevels: 'Both the temporary hit points and cold damage increase by 5 for each slot level above 1st.', classes: ['warlock'], damageType: 'cold', tags: ['defense', 'temp-hp'] },
  { id: 'command', name: 'Command', level: 1, school: 'Enchantment', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V'], duration: '1 round', concentration: false, ritual: false, description: 'You speak a one-word command to a creature you can see within range. The target must succeed on a Wisdom saving throw or follow the command on its next turn. The spell has no effect if the target is undead, if it doesn\'t understand your language, or if your command is directly harmful to it.\n\nSome typical commands and their effects follow. You might issue a command other than one described here. If you do so, the DM determines how the target behaves. Drop. The target drops whatever it is holding and then ends its turn. Flee. The target spends its turn moving away from you by the fastest available means. Grovel. The target falls prone and then ends its turn. Halt. The target doesn\'t move and takes no actions. Approach. The target moves toward you by the shortest and most direct route, ending its turn if it moves within 5 feet of you.\n\nAt Higher Levels: When you cast this spell using a spell slot of 2nd level or higher, you can affect one additional creature for each slot level above 1st.', atHigherLevels: 'Affect one additional creature for each slot level above 1st.', classes: ['cleric', 'paladin'], savingThrow: 'wis', tags: ['control', 'enchantment'] },
  { id: 'comprehend-languages', name: 'Comprehend Languages', level: 1, school: 'Divination', sourceBook: 'PHB', castingTime: '1 action', range: 'Self', components: ['V', 'S', 'M'], materialComponent: 'a pinch of soot and salt', duration: '1 hour', concentration: false, ritual: true, description: 'For the duration, you understand the literal meaning of any spoken language that you hear. You also understand any written language that you see, but you must be touching the surface on which the words are written. It takes about 1 minute to read one page of text.\n\nThis spell doesn\'t decode secret messages in a text or a glyph, such as an arcane sigil, that isn\'t part of a written language.', classes: ['bard', 'sorcerer', 'warlock', 'wizard'], tags: ['utility', 'ritual'] },
  { id: 'disguise-self', name: 'Disguise Self', level: 1, school: 'Illusion', sourceBook: 'PHB', castingTime: '1 action', range: 'Self', components: ['V', 'S'], duration: '1 hour', concentration: false, ritual: false, description: 'You make yourself—including your clothing, armor, weapons, and other belongings on your person—look different until the spell ends or until you use your action to dismiss it. You can seem 1 foot shorter or taller and can appear thin, fat, or in between. You can\'t change your body type, so you must adopt a form that has the same basic arrangement of limbs. Otherwise, the extent of the illusion is up to you.\n\nThe changes wrought by this spell fail to hold up to physical inspection. For example, if you use this spell to add a hat to your outfit, objects pass through the hat, and anyone who touches it would feel nothing or would feel your head and hair. If you use this spell to appear thinner than you are, the hand of someone who reaches out to touch you would bump into you while it was seemingly still in midair.\n\nTo discern that you are disguised, a creature can use its action to inspect your appearance and must succeed on an Intelligence (Investigation) check against your spell save DC.', classes: ['bard', 'sorcerer', 'wizard'], tags: ['illusion', 'utility'] },
  { id: 'entangle', name: 'Entangle', level: 1, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 action', range: '90 feet', components: ['V', 'S'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'Grasping weeds and vines sprout from the ground in a 20-foot square starting from a point within range. For the duration, these plants turn the ground in the area into difficult terrain.\n\nA creature in the area when you cast the spell must succeed on a Strength saving throw or be restrained by the entangling plants until the spell ends. A creature restrained by the plants can use its action to make a Strength check against your spell save DC. On a success, it frees itself.\n\nWhen the spell ends, the conjured plants wilt away.', classes: ['druid'], savingThrow: 'str', tags: ['control', 'difficult-terrain'] },
  { id: 'faerie-fire', name: 'Faerie Fire', level: 1, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'Each object in a 20-foot cube within range is outlined in blue, green, or violet light (your choice). Any creature in the area when the spell is cast is also outlined in light if it fails a Dexterity saving throw. For the duration, objects and affected creatures shed dim light in a 10-foot radius.\n\nAny attack roll against an affected creature or object has advantage if the attacker can see it, and the affected creature or object can\'t benefit from being invisible.', classes: ['bard', 'druid'], savingThrow: 'dex', tags: ['control', 'buff'] },
  { id: 'feather-fall', name: 'Feather Fall', level: 1, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 reaction', range: '60 feet', components: ['V', 'M'], materialComponent: 'a small feather or piece of down', duration: '1 minute', concentration: false, ritual: false, description: 'Choose up to five falling creatures within range. A falling creature\'s rate of descent slows to 60 feet per round until the spell ends. If the creature lands before the spell ends, it takes no falling damage and can land on its feet, and the spell ends for that creature.', classes: ['bard', 'sorcerer', 'wizard'], tags: ['utility', 'reaction'] },
  { id: 'fog-cloud', name: 'Fog Cloud', level: 1, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 action', range: '120 feet', components: ['V', 'S'], duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: 'You create a 20-foot-radius sphere of fog centered on a point within range. The sphere spreads around corners, and its area is heavily obscured. It lasts for the duration or until a wind of moderate or greater speed (at least 10 miles per hour) disperses it.\n\nAt Higher Levels: When you cast this spell using a spell slot of 2nd level or higher, the radius of the fog increases by 20 feet for each slot level above 1st.', atHigherLevels: 'The radius of the fog increases by 20 feet for each slot level above 1st.', classes: ['druid', 'ranger', 'sorcerer', 'wizard'], tags: ['control', 'obscurement'] },
  { id: 'goodberry', name: 'Goodberry', level: 1, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'a sprig of mistletoe', duration: 'Instantaneous', concentration: false, ritual: false, description: 'Up to ten berries appear in your hand and are infused with magic for the duration. A creature can use its action to eat one berry. Eating a berry restores 1 hit point, and the berry provides enough nourishment to sustain a creature for one day.\n\nThe berries lose their potency if they have not been consumed within 24 hours of the casting of this spell.', classes: ['druid', 'ranger'], tags: ['healing', 'utility'] },
  { id: 'hellish-rebuke', name: 'Hellish Rebuke', level: 1, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 reaction', range: '60 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You point your finger, and the creature that damaged you is momentarily surrounded by hellish flames. The creature must make a Dexterity saving throw. It takes 2d10 fire damage on a failed save, or half as much damage on a successful one.\n\nAt Higher Levels: When you cast this spell using a spell slot of 2nd level or higher, the damage increases by 1d10 for each slot level above 1st.', atHigherLevels: 'Damage increases by 1d10 for each slot level above 1st.', classes: ['warlock'], damageType: 'fire', savingThrow: 'dex', tags: ['damage', 'reaction'] },
  { id: 'longstrider', name: 'Longstrider', level: 1, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'a pinch of dirt', duration: '1 hour', concentration: false, ritual: false, description: 'You touch a creature. The target\'s speed increases by 10 feet until the spell ends.\n\nAt Higher Levels: When you cast this spell using a spell slot of 2nd level or higher, you can target one additional creature for each slot level above 1st.', atHigherLevels: 'Target one additional creature for each slot level above 1st.', classes: ['bard', 'druid', 'ranger', 'wizard'], tags: ['buff', 'movement'] },
  { id: 'protection-from-evil-good', name: 'Protection from Evil and Good', level: 1, school: 'Abjuration', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'holy water or powdered silver and iron, which the spell consumes', duration: 'Concentration, up to 10 minutes', concentration: true, ritual: false, description: 'Until the spell ends, one willing creature you touch is protected against certain types of creatures: aberrations, celestials, elementals, fey, fiends, and undead.\n\nThe protection grants several benefits. Creatures of those types have disadvantage on attack rolls against the target. The target also can\'t be charmed, frightened, or possessed by them. If the target is already charmed, frightened, or possessed by such a creature, the target has advantage on any new saving throw against the relevant effect.', classes: ['cleric', 'paladin', 'warlock', 'wizard'], tags: ['defense', 'abjuration'] },
  { id: 'speak-with-animals', name: 'Speak with Animals', level: 1, school: 'Divination', sourceBook: 'PHB', castingTime: '1 action', range: 'Self', components: ['V', 'S'], duration: '10 minutes', concentration: false, ritual: true, description: 'You gain the ability to comprehend and verbally communicate with beasts for the duration. The knowledge and awareness of many beasts is limited by their intelligence, but at minimum, beasts can give you information about nearby locations and monsters, including whatever they can perceive or have perceived within the past day. You might be able to persuade a beast to perform a small favor for you, at the DM\'s discretion.', classes: ['bard', 'druid', 'ranger'], tags: ['utility', 'ritual'] },
  { id: 'tashas-hideous-laughter', name: "Tasha's Hideous Laughter", level: 1, school: 'Enchantment', sourceBook: 'PHB', castingTime: '1 action', range: '30 feet', components: ['V', 'S', 'M'], materialComponent: 'tiny tarts and a feather that is waved in the air', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'A creature of your choice that you can see within range perceives everything as hilariously funny and falls into fits of laughter if this spell affects it. The target must succeed on a Wisdom saving throw or fall prone, becoming incapacitated and unable to stand up for the duration. A creature with an Intelligence score of 4 or less isn\'t affected.\n\nAt the end of each of its turns, and each time it takes damage, the target can make another Wisdom saving throw. The target has advantage on the saving throw if it\'s triggered by damage. On a success, the spell ends.', classes: ['bard', 'wizard'], savingThrow: 'wis', tags: ['control', 'enchantment'] },
  { id: 'unseen-servant', name: 'Unseen Servant', level: 1, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S', 'M'], materialComponent: 'a piece of string and a bit of wood', duration: '1 hour', concentration: false, ritual: true, description: 'This spell creates an invisible, mindless, shapeless, Medium force that performs simple tasks at your command until the spell ends. The servant springs into existence in an unoccupied space on the ground within range. It has AC 10, 1 hit point, and a Strength of 2, and it can\'t attack. If it drops to 0 hit points, the spell ends.\n\nOnce on each of your turns as a bonus action, you can mentally command the servant to move up to 15 feet and interact with an object. The servant can perform simple tasks that a human servant could do, such as fetching things, cleaning, mending, folding clothes, lighting fires, serving food, and pouring wine. Once you give the command, the servant performs the task to the best of its ability until it completes the task, then waits for your next command.', classes: ['bard', 'warlock', 'wizard'], tags: ['utility', 'ritual'] },
  { id: 'witch-bolt', name: 'Witch Bolt', level: 1, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '30 feet', components: ['V', 'S', 'M'], materialComponent: 'a twig from a tree that has been struck by lightning', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'A beam of crackling, blue energy lances out toward a creature within range, forming a sustained arc of lightning between you and the target. Make a ranged spell attack against that creature. On a hit, the target takes 1d12 lightning damage, and on each of your turns for the duration, you can use your action to deal 1d12 lightning damage to the target automatically. The spell ends if you use your action to do anything else. The spell also ends if the target is ever outside the spell\'s range or if it has total cover from you.\n\nAt Higher Levels: When you cast this spell using a spell slot of 2nd level or higher, the initial damage increases by 1d12 for each slot level above 1st.', atHigherLevels: 'Initial damage increases by 1d12 for each slot level above 1st.', classes: ['sorcerer', 'warlock', 'wizard'], damageType: 'lightning', tags: ['damage', 'sustained'] },
  { id: 'false-life', name: 'False Life', level: 1, school: 'Necromancy', sourceBook: 'PHB', castingTime: '1 action', range: 'Self', components: ['V', 'S', 'M'], materialComponent: 'a small amount of alcohol or distilled spirits', duration: '1 hour', concentration: false, ritual: false, description: 'Bolstering yourself with a necromantic facsimile of life, you gain 1d4+4 temporary hit points for the duration.\n\nAt Higher Levels: When you cast this spell using a spell slot of 2nd level or higher, you gain 5 additional temporary hit points for each slot level above 1st.', atHigherLevels: 'Gain 5 additional temporary hit points for each slot level above 1st.', classes: ['sorcerer', 'wizard'], tags: ['defense', 'temp-hp'] },
  { id: 'expeditious-retreat', name: 'Expeditious Retreat', level: 1, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 bonus action', range: 'Self', components: ['V', 'S'], duration: 'Concentration, up to 10 minutes', concentration: true, ritual: false, description: 'This spell allows you to move at an incredible pace. When you cast this spell, and then as a bonus action on each of your turns until the spell ends, you can take the Dash action.', classes: ['sorcerer', 'warlock', 'wizard'], tags: ['movement', 'buff'] },
  { id: 'silent-image', name: 'Silent Image', level: 1, school: 'Illusion', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S', 'M'], materialComponent: 'a bit of fleece', duration: 'Concentration, up to 10 minutes', concentration: true, ritual: false, description: 'You create the image of an object, a creature, or some other visible phenomenon that is no larger than a 15-foot cube. The image appears at a spot within range and lasts for the duration. The image is purely visual; it isn\'t accompanied by sound, smell, or other sensory effects.\n\nYou can use your action to cause the image to move to any spot within range. As the image changes location, you can alter its appearance so that its movements appear natural for the image. For example, if you create an image of a creature and move it, you can alter the image so that it appears to be walking.', classes: ['bard', 'sorcerer', 'wizard'], tags: ['illusion', 'utility'] },
  { id: 'animal-friendship', name: 'Animal Friendship', level: 1, school: 'Enchantment', sourceBook: 'PHB', castingTime: '1 action', range: '30 feet', components: ['V', 'S', 'M'], materialComponent: 'a morsel of food', duration: '24 hours', concentration: false, ritual: false, description: 'This spell lets you convince a beast that you mean it no harm. Choose a beast that you can see within range. It must see and hear you. If the beast\'s Intelligence is 4 or higher, the spell fails. Otherwise, the beast must succeed on a Wisdom saving throw or be charmed by you for the spell\'s duration. If you or one of your companions harms the target, the spell ends.\n\nAt Higher Levels: When you cast this spell using a spell slot of 2nd level or higher, you can affect one additional beast for each slot level above 1st.', atHigherLevels: 'Affect one additional beast for each slot level above 1st.', classes: ['bard', 'druid', 'ranger'], savingThrow: 'wis', tags: ['social', 'enchantment'] },

  // ── ADDITIONAL LEVEL 2 SPELLS ────────────────────────────────────────────
  { id: 'aid', name: 'Aid', level: 2, school: 'Abjuration', sourceBook: 'PHB', castingTime: '1 action', range: '30 feet', components: ['V', 'S', 'M'], materialComponent: 'a tiny strip of white cloth', duration: '8 hours', concentration: false, ritual: false, description: 'Your spell bolsters your allies with toughness and resolve. Choose up to three creatures within range. Each target\'s hit point maximum and current hit points increase by 5 for the duration.\n\nAt Higher Levels: When you cast this spell using a spell slot of 3rd level or higher, a target\'s hit points increase by an additional 5 for each slot level above 2nd.', atHigherLevels: 'Each target\'s hit points increase by an additional 5 for each slot level above 2nd.', classes: ['cleric', 'paladin'], tags: ['buff', 'healing'] },
  { id: 'blindness-deafness', name: 'Blindness/Deafness', level: 2, school: 'Necromancy', sourceBook: 'PHB', castingTime: '1 action', range: '30 feet', components: ['V'], duration: '1 minute', concentration: false, ritual: false, description: 'You can blind or deafen a foe. Choose one creature that you can see within range to make a Constitution saving throw. If it fails, the target is either blinded or deafened (your choice) for the duration. At the end of each of its turns, the target can make a Constitution saving throw. On a success, the spell ends.\n\nAt Higher Levels: When you cast this spell using a spell slot of 3rd level or higher, you can target one additional creature for each slot level above 2nd.', atHigherLevels: 'Target one additional creature for each slot level above 2nd.', classes: ['bard', 'cleric', 'sorcerer', 'wizard'], savingThrow: 'con', tags: ['control', 'debuff'] },
  { id: 'darkness', name: 'Darkness', level: 2, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'M'], materialComponent: 'bat fur and a drop of pitch or piece of coal', duration: 'Concentration, up to 10 minutes', concentration: true, ritual: false, description: 'Magical darkness spreads from a point you choose within range to fill a 15-foot-radius sphere for the duration. The darkness spreads around corners. A creature with darkvision can\'t see through this magical darkness, and nonmagical light can\'t illuminate it.\n\nIf the point you choose is on an object you are holding or one that isn\'t being worn or carried, the darkness emanates from the object and moves with it. Completely covering the source of the darkness with an opaque object, such as a bowl or a helm, blocks the darkness.\n\nIf any of this spell\'s area overlaps with an area of light created by a spell of 2nd level or lower, the spell that created the light is dispelled.', classes: ['sorcerer', 'warlock', 'wizard'], tags: ['control', 'obscurement'] },
  { id: 'darkvision', name: 'Darkvision', level: 2, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'either a pinch of dried carrot or an agate', duration: '8 hours', concentration: false, ritual: false, description: 'You touch a willing creature to grant it the ability to see in the dark. For the duration, that creature has darkvision out to a range of 60 feet.', classes: ['druid', 'ranger', 'sorcerer', 'wizard'], tags: ['utility', 'buff'] },
  { id: 'enhance-ability', name: 'Enhance Ability', level: 2, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'fur or a feather from a beast', duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: "You touch a creature and bestow upon it a magical enhancement. Choose one of the following effects; the target gains that effect until the spell ends.\n\nBear's Endurance: The target has advantage on Constitution checks. It also gains 2d6 temporary hit points, which are lost when the spell ends.\n\nBull's Strength: The target has advantage on Strength checks, and his or her carrying capacity doubles.\n\nCat's Grace: The target has advantage on Dexterity checks. It also doesn't take damage from falling 20 feet or less if it isn't incapacitated.\n\nEagle's Splendor: The target has advantage on Charisma checks.\n\nFox's Cunning: The target has advantage on Intelligence checks.\n\nOwl's Wisdom: The target has advantage on Wisdom checks.", classes: ['bard', 'cleric', 'druid', 'sorcerer', 'wizard'], tags: ['buff', 'utility'] },
  { id: 'enlarge-reduce', name: 'Enlarge/Reduce', level: 2, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: '30 feet', components: ['V', 'S', 'M'], materialComponent: 'a pinch of powdered iron', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You cause a creature or an object you can see within range to grow larger or smaller for the duration. Choose either a creature or a non-magical object that is neither worn nor carried. If the target is unwilling, it can make a Constitution saving throw. On a success, the spell has no effect.\n\nEnlarge: The target\'s size doubles in all dimensions, and its weight is multiplied by eight. This growth increases its size by one category— from Medium to Large, for example. The target also has advantage on Strength checks and Strength saving throws. The target\'s weapons also grow to match its new size. While these weapons are enlarged, the target\'s attacks with them deal 1d4 extra damage.\n\nReduce: The target\'s size is halved in all dimensions, and its weight is reduced to one-eighth of normal. This reduction decreases its size by one category. The target also has disadvantage on Strength checks and Strength saving throws. The target\'s weapons also shrink to match its new size. While these weapons are reduced, the target\'s attacks with them deal 1d4 less damage (this can\'t reduce the damage below 1).', classes: ['sorcerer', 'wizard'], savingThrow: 'con', tags: ['control', 'buff', 'debuff'] },
  { id: 'pass-without-trace', name: 'Pass Without Trace', level: 2, school: 'Abjuration', sourceBook: 'PHB', castingTime: '1 action', range: 'Self', components: ['V', 'S', 'M'], materialComponent: 'ashes from a burned leaf of mistletoe and a sprig of spruce', duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: 'A veil of shadows and silence radiates from you, masking you and your companions from detection. For the duration, each creature you choose within 30 feet of you (including you) has a +10 bonus to Dexterity (Stealth) checks and can\'t be tracked except by magical means. A creature that receives this bonus leaves behind no tracks or other traces of its passage.', classes: ['druid', 'ranger'], tags: ['stealth', 'buff'] },
  { id: 'see-invisibility', name: 'See Invisibility', level: 2, school: 'Divination', sourceBook: 'PHB', castingTime: '1 action', range: 'Self', components: ['V', 'S', 'M'], materialComponent: 'a pinch of talc and a small sprinkling of powdered silver', duration: '1 hour', concentration: false, ritual: false, description: 'For the duration, you see invisible creatures and objects as if they were visible, and you can see into the Ethereal Plane. Ethereal creatures and objects appear ghostly and translucent.', classes: ['bard', 'sorcerer', 'wizard'], tags: ['utility', 'detection'] },
  { id: 'silence', name: 'Silence', level: 2, school: 'Illusion', sourceBook: 'PHB', castingTime: '1 action', range: '120 feet', components: ['V', 'S'], duration: 'Concentration, up to 10 minutes', concentration: true, ritual: true, description: 'For the duration, no sound can be created within or pass through a 20-foot-radius sphere centered on a point you choose within range. Any creature or object entirely inside the sphere is immune to thunder damage, and creatures are deafened while entirely inside it. Casting a spell that includes a verbal component is impossible there.', classes: ['bard', 'cleric', 'ranger'], tags: ['control', 'ritual'] },
  { id: 'suggestion', name: 'Suggestion', level: 2, school: 'Enchantment', sourceBook: 'PHB', castingTime: '1 action', range: '30 feet', components: ['V', 'M'], materialComponent: "a snake's tongue and either a bit of honeycomb or a drop of sweet oil", duration: 'Concentration, up to 8 hours', concentration: true, ritual: false, description: 'You suggest a course of activity (limited to a sentence or two) and magically influence a creature you can see within range that can hear and understand you. Creatures that can\'t be charmed are immune to this effect. The suggestion must be worded in such a manner as to make the course of action sound reasonable. Asking the creature to stab itself, throw itself onto a spear, immolate itself, or do some other obviously harmful act automatically negates the effect of the spell.\n\nThe target must make a Wisdom saving throw. On a failed save, it pursues the course of action you described to the best of its ability. The suggested course of action can continue for the entire duration. If the suggested activity can be completed in a shorter time, the spell ends when the subject finishes what it was asked to do.', classes: ['bard', 'sorcerer', 'warlock', 'wizard'], savingThrow: 'wis', tags: ['control', 'enchantment', 'social'] },
  { id: 'web', name: 'Web', level: 2, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S', 'M'], materialComponent: 'a bit of spiderweb', duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: 'You conjure a mass of thick, sticky webbing at a point of your choice within range. The webs fill a 20-foot cube from that point for the duration. The webs are difficult terrain and lightly obscure their area.\n\nIf the webs aren\'t anchored between two solid masses (such as walls or trees) or layered across a floor, wall, or ceiling, the conjured web collapses on itself, and the spell ends at the start of your next turn. Webs layered over a flat surface have a depth of 5 feet.\n\nEach creature that starts its turn in the webs or that enters them during its turn must make a Dexterity saving throw. On a failed save, the creature is restrained as long as it remains in the webs or until it breaks free.\n\nA creature restrained by the webs can use its action to make a Strength check against your spell save DC. If it succeeds, it is no longer restrained.', classes: ['sorcerer', 'wizard'], savingThrow: 'dex', tags: ['control', 'difficult-terrain'] },
  { id: 'heat-metal', name: 'Heat Metal', level: 2, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S', 'M'], materialComponent: 'a piece of iron and a flame', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'Choose a manufactured metal object, such as a metal weapon or a suit of heavy or medium metal armor, that you can see within range. You cause the object to glow red-hot. Any creature in physical contact with the object takes 2d8 fire damage when you cast the spell. Until the spell ends, you can use a bonus action on each of your subsequent turns to cause this damage again.\n\nIf a creature is holding or wearing the object and takes the damage from it, the creature must succeed on a Constitution saving throw or drop the object if it can. If it doesn\'t drop the object, it has disadvantage on attack rolls and ability checks until the start of your next turn.\n\nAt Higher Levels: When you cast this spell using a spell slot of 3rd level or higher, the damage increases by 1d8 for each slot level above 2nd.', atHigherLevels: 'Damage increases by 1d8 for each slot level above 2nd.', classes: ['druid'], damageType: 'fire', savingThrow: 'con', tags: ['damage', 'control'] },
  { id: 'levitate', name: 'Levitate', level: 2, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S', 'M'], materialComponent: 'either a small leather loop or a piece of golden wire bent into a cup shape with a long shank on one end', duration: 'Concentration, up to 10 minutes', concentration: true, ritual: false, description: 'One creature or object of your choice that you can see within range rises vertically, up to 20 feet, and remains suspended there for the duration. The spell can levitate a target that weighs up to 500 pounds. An unwilling creature that succeeds on a Constitution saving throw is unaffected.\n\nThe target can move only by pushing or pulling against a fixed object or surface within reach (such as a wall or a ceiling), which allows it to move as if it were climbing. You can change the target\'s altitude by up to 20 feet in either direction on your turn. If you are the target, you can move up or down as part of your move. Otherwise, you can use your action to move the target, which must remain within the spell\'s range.\n\nWhen the spell ends, the target floats gently to the ground if it is still aloft.', classes: ['sorcerer', 'wizard'], savingThrow: 'con', tags: ['control', 'utility'] },

  // ── ADDITIONAL LEVEL 3 SPELLS ────────────────────────────────────────────
  { id: 'animate-dead', name: 'Animate Dead', level: 3, school: 'Necromancy', sourceBook: 'PHB', castingTime: '1 minute', range: '10 feet', components: ['V', 'S', 'M'], materialComponent: 'a drop of blood, a piece of flesh, and a pinch of bone dust', duration: 'Instantaneous', concentration: false, ritual: false, description: 'This spell creates an undead servant. Choose a pile of bones or a corpse of a Medium or Small humanoid within range. Your spell imbues the target with a foul mimicry of life, raising it as an undead creature. The target becomes a skeleton if you chose bones or a zombie if you chose a corpse.\n\nOn each of your turns, you can use a bonus action to mentally command any creature you made with this spell if the creature is within 60 feet of you.\n\nAt Higher Levels: When you cast this spell using a spell slot of 4th level or higher, you animate or reassert control over two additional undead creatures for each slot level above 3rd.', atHigherLevels: 'Animate two additional undead for each slot level above 3rd.', classes: ['cleric', 'wizard'], tags: ['necromancy', 'summoning'] },
  { id: 'bestow-curse', name: 'Bestow Curse', level: 3, school: 'Necromancy', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You touch a creature, and that creature must succeed on a Wisdom saving throw or become cursed for the duration of the spell. When you cast this spell, choose the nature of the curse from the following options:\n\n• Choose one ability score. While cursed, the target has disadvantage on ability checks and saving throws made with that ability score.\n• While cursed, the target has disadvantage on attack rolls against you.\n• While cursed, the target must make a Wisdom saving throw at the start of each of its turns. If it fails, it wastes its action that turn doing nothing.\n• While the target is cursed, your attacks and spells deal an extra 1d8 necrotic damage to the target.\n\nAt Higher Levels: If you cast this spell using a spell slot of 4th level or higher, the duration is 10 minutes. If you use a spell slot of 5th level or higher, the duration is 8 hours.', atHigherLevels: '4th level: 10 minutes. 5th+ level: 8 hours. Both without concentration.', classes: ['cleric', 'wizard'], savingThrow: 'wis', tags: ['debuff', 'curse'] },
  { id: 'call-lightning', name: 'Call Lightning', level: 3, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 action', range: '120 feet', components: ['V', 'S'], duration: 'Concentration, up to 10 minutes', concentration: true, ritual: false, description: 'A storm cloud appears in the shape of a cylinder that is 10 feet tall with a 60-foot radius, centered on a point you can see 100 feet directly above you. The spell fails if you can\'t see a point in the air where the storm cloud could appear.\n\nWhen you cast the spell, choose a point you can see within range. A bolt of lightning flashes down from the cloud to that point. Each creature within 5 feet of that point must make a Dexterity saving throw. A creature takes 3d10 lightning damage on a failed save, or half as much damage on a successful one.\n\nOn each of your turns until the spell ends, you can use your action to call down lightning in this way again, targeting the same point or a different one.\n\nAt Higher Levels: When you cast this spell using a spell slot of 4th or higher level, the damage increases by 1d10 for each slot level above 3rd.', atHigherLevels: 'Damage increases by 1d10 for each slot level above 3rd.', classes: ['druid'], damageType: 'lightning', savingThrow: 'dex', tags: ['damage', 'aoe', 'sustained'] },
  { id: 'fear', name: 'Fear', level: 3, school: 'Illusion', sourceBook: 'PHB', castingTime: '1 action', range: 'Self', components: ['V', 'S', 'M'], materialComponent: 'a white feather or the heart of a hen', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You project a phantasmal image of a creature\'s worst fears. Each creature in a 30-foot cone must succeed on a Wisdom saving throw or drop whatever it is holding and become frightened for the duration.\n\nWhile frightened by this spell, a creature must take the Dash action and move away from you by the safest available route on each of its turns, unless there is nowhere to move. If the creature ends its turn in a location where it doesn\'t have line of sight to you, the creature can make a Wisdom saving throw. On a successful save, the spell ends for that creature.', classes: ['bard', 'sorcerer', 'warlock', 'wizard'], savingThrow: 'wis', tags: ['control', 'fear'] },
  { id: 'hypnotic-pattern', name: 'Hypnotic Pattern', level: 3, school: 'Illusion', sourceBook: 'PHB', castingTime: '1 action', range: '120 feet', components: ['S', 'M'], materialComponent: 'a glowing stick of incense or a crystal vial filled with phosphorescent material', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You create a twisting pattern of colors that weaves through the air inside a 30-foot cube within range. The pattern appears for a moment and vanishes. Each creature in the area who sees the pattern must make a Wisdom saving throw. On a failed save, the creature becomes charmed for the duration. While charmed by this spell, the creature is incapacitated and has a speed of 0.\n\nThe spell ends for an affected creature if it takes any damage or if someone else uses an action to shake the creature out of its stupor.', classes: ['bard', 'sorcerer', 'warlock', 'wizard'], savingThrow: 'wis', tags: ['control', 'enchantment'] },
  { id: 'plant-growth', name: 'Plant Growth', level: 3, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action or 8 hours', range: '150 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'This spell channels vitality into plants within a specific area. There are two possible uses for the spell, granting either immediate or long-term benefits.\n\nIf you cast this spell using 1 action, choose a point within range. All normal plants in a 100-foot radius centered on that point become thick and overgrown. A creature moving through the area must spend 4 feet of movement for every 1 foot it moves.\n\nIf you cast this spell over 8 hours, you enrich the land. All plants in a half-mile radius centered on a point within range become enriched for 1 year. The plants yield twice the normal amount of food when harvested.', classes: ['bard', 'druid', 'ranger'], tags: ['control', 'difficult-terrain', 'utility'] },
  { id: 'protection-from-energy', name: 'Protection from Energy', level: 3, school: 'Abjuration', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S'], duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: 'For the duration, the willing creature you touch has resistance to one damage type of your choice: acid, cold, fire, lightning, or thunder.', classes: ['cleric', 'druid', 'ranger', 'sorcerer', 'wizard'], tags: ['defense', 'resistance'] },
  { id: 'sending', name: 'Sending', level: 3, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: 'Unlimited', components: ['V', 'S', 'M'], materialComponent: 'a short piece of fine copper wire', duration: '1 round', concentration: false, ritual: false, description: 'You send a short message of twenty-five words or less to a creature with which you are familiar. The creature hears the message in its mind, recognizes you as the sender if it knows you, and can answer in a like manner immediately. The spell enables creatures with Intelligence scores of at least 1 to understand the meaning of your message.\n\nYou can send the message across any distance and even to other planes of existence, but if the target is on a different plane than you, there is a 5 percent chance that the message doesn\'t arrive.', classes: ['bard', 'cleric', 'wizard'], tags: ['utility', 'communication'] },
  { id: 'slow', name: 'Slow', level: 3, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: '120 feet', components: ['V', 'S', 'M'], materialComponent: 'a drop of molasses', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You alter time around up to six creatures of your choice in a 40-foot cube within range. Each target must succeed on a Wisdom saving throw or be affected by this spell for the duration.\n\nAn affected target\'s speed is halved, it takes a −2 penalty to AC and Dexterity saving throws, and it can\'t use reactions. On its turn, it can use either an action or a bonus action, not both. Regardless of the creature\'s abilities or magic items, it can\'t make more than one melee or ranged attack during its turn.\n\nIf the creature attempts to cast a spell with a casting time of 1 action, roll a d20. On an 11 or higher, the spell doesn\'t take effect until the creature\'s next turn, and the creature must use its action on that turn to complete the spell. If it can\'t, the spell is wasted.', classes: ['sorcerer', 'wizard'], savingThrow: 'wis', tags: ['control', 'debuff'] },
  { id: 'speak-with-dead', name: 'Speak with Dead', level: 3, school: 'Necromancy', sourceBook: 'PHB', castingTime: '1 action', range: '10 feet', components: ['V', 'S', 'M'], materialComponent: 'burning incense', duration: '10 minutes', concentration: false, ritual: false, description: 'You grant the semblance of life and intelligence to a corpse of your choice within range, allowing it to answer the questions you pose. The corpse must still have a mouth and can\'t be undead. The spell fails if the corpse was the target of this spell within the last 10 days.\n\nUntil the spell ends, you can ask the corpse up to five questions. The corpse knows only what it knew in life, including the languages it knew. Answers are usually brief, cryptic, or repetitive, and the corpse is under no compulsion to offer a truthful answer if you are hostile to it or it recognizes you as an enemy.', classes: ['bard', 'cleric'], tags: ['utility', 'necromancy', 'ritual'] },
  { id: 'stinking-cloud', name: 'Stinking Cloud', level: 3, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 action', range: '90 feet', components: ['V', 'S', 'M'], materialComponent: 'a rotten egg or several skunk cabbage leaves', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You create a 20-foot-radius sphere of yellow, nauseating gas centered on a point within range. The cloud spreads around corners, and its area is heavily obscured. The cloud lingers in the air for the duration.\n\nEach creature that is completely within the cloud at the start of its turn must make a Constitution saving throw against poison. On a failed save, the creature spends its action that turn retching and reeling. Creatures that don\'t need to breathe or are immune to poison automatically succeed on this saving throw.', classes: ['bard', 'sorcerer', 'wizard'], savingThrow: 'con', tags: ['control', 'aoe'] },
  { id: 'tongues', name: 'Tongues', level: 3, school: 'Divination', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'M'], materialComponent: 'a small clay model of a ziggurat', duration: '1 hour', concentration: false, ritual: false, description: 'This spell grants the creature you touch the ability to understand any spoken language it hears. Moreover, when the target speaks, any creature that knows at least one language and can hear the target understands what it says.', classes: ['bard', 'cleric', 'sorcerer', 'warlock', 'wizard'], tags: ['utility', 'communication'] },
  { id: 'vampiric-touch', name: 'Vampiric Touch', level: 3, school: 'Necromancy', sourceBook: 'PHB', castingTime: '1 action', range: 'Self', components: ['V', 'S'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'The touch of your shadow-wreathed hand can siphon life force from others to heal your wounds. Make a melee spell attack against a creature within your reach. On a hit, the target takes 3d6 necrotic damage, and you regain hit points equal to half the amount of necrotic damage dealt. Until the spell ends, you can make the attack again on each of your turns as an action.\n\nAt Higher Levels: When you cast this spell using a spell slot of 4th level or higher, the damage increases by 1d6 for each slot level above 3rd.', atHigherLevels: 'Damage increases by 1d6 for each slot level above 3rd.', classes: ['warlock', 'wizard'], damageType: 'necrotic', tags: ['damage', 'healing', 'melee'] },
  { id: 'leomund-tiny-hut', name: "Leomund's Tiny Hut", level: 3, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 minute', range: 'Self', components: ['V', 'S', 'M'], materialComponent: 'a small crystal bead', duration: '8 hours', concentration: false, ritual: true, description: 'A 10-foot-radius immobile dome of force springs into existence around and above you and remains stationary for the duration. The spell ends if you leave its area.\n\nNine creatures of Medium size or smaller can fit inside the dome with you. The spell fails if its area includes a larger creature or more than nine creatures. Creatures and objects within the dome when you cast this spell can move through it freely. All other creatures and objects are barred from passing through it. Spells and other magical effects can\'t extend through the dome or be cast through it. The atmosphere inside the space is comfortable and dry, regardless of the weather outside.\n\nUntil the spell ends, you can command the interior to become dimly lit or dark. The dome is opaque from the outside, of any color you choose, but it is transparent from the inside.', classes: ['bard', 'wizard'], tags: ['utility', 'ritual', 'protection'] },
  { id: 'daylight', name: 'Daylight', level: 3, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S'], duration: '1 hour', concentration: false, ritual: false, description: 'A 60-foot-radius sphere of light spreads out from a point you choose within range. The sphere is bright light and sheds dim light for an additional 60 feet.\n\nIf you chose a point on an object you are holding or one that isn\'t being worn or carried, the light shines from the object with and moves with it. Completely covering the affected object with an opaque object, such as a bowl or a helm, blocks the light.\n\nIf any of this spell\'s area overlaps with an area of magical darkness created by a spell of 3rd level or lower, the spell that created the darkness is dispelled.', classes: ['cleric', 'druid', 'paladin', 'ranger', 'sorcerer'], tags: ['utility', 'light'] },

  // ── ADDITIONAL LEVEL 4 SPELLS ────────────────────────────────────────────
  { id: 'arcane-eye', name: 'Arcane Eye', level: 4, school: 'Divination', sourceBook: 'PHB', castingTime: '1 action', range: '30 feet', components: ['V', 'S', 'M'], materialComponent: 'a bit of bat fur', duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: 'You create an invisible, magical eye within range that hovers in the air for the duration.\n\nYou mentally receive visual information from the eye, which has normal vision and darkvision out to 30 feet. The eye can look in every direction.\n\nAs an action, you can move the eye up to 30 feet in any direction. There is no limit to how far away from you the eye can move, but it can\'t enter another plane of existence. A solid barrier blocks the eye\'s movement, but the eye can pass through an opening as small as 1 inch in diameter.', classes: ['wizard'], tags: ['utility', 'scouting'] },
  { id: 'compulsion', name: 'Compulsion', level: 4, school: 'Enchantment', sourceBook: 'PHB', castingTime: '1 action', range: '30 feet', components: ['V', 'S'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'Creatures of your choice that you can see within range and that can hear you must make a Wisdom saving throw. A target automatically succeeds on this saving throw if it can\'t be charmed. On a failed save, a target is affected by this spell. Until the spell ends, you can use a bonus action on each of your turns to designate a direction that is horizontal to you. Each affected target must use as much of its movement as possible to move in that direction on its next turn. It can take its action before it moves. After moving in this way, it can make another Wisdom saving throw to try to end the effect.', classes: ['bard'], savingThrow: 'wis', tags: ['control', 'enchantment'] },
  { id: 'death-ward', name: 'Death Ward', level: 4, school: 'Abjuration', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S'], duration: '8 hours', concentration: false, ritual: false, description: 'You touch a creature and grant it a measure of protection from death.\n\nThe first time the target would drop to 0 hit points as a result of taking damage, the target instead drops to 1 hit point, and the spell ends.\n\nIf the spell is still in effect when the target is subjected to an effect that would kill it instantaneously without dealing damage, that effect is instead negated against the target, and the spells ends.', classes: ['cleric', 'paladin'], tags: ['defense', 'buff'] },
  { id: 'evards-black-tentacles', name: "Evard's Black Tentacles", level: 4, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 action', range: '90 feet', components: ['V', 'S', 'M'], materialComponent: "a piece of tentacle from a giant octopus or a giant squid", duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'Squirming, ebony tentacles fill a 20-foot square on ground that you can see within range. For the duration, these tentacles turn the ground in the area into difficult terrain.\n\nWhen a creature enters the affected area for the first time on a turn or starts its turn there, the creature must succeed on a Dexterity saving throw or take 3d6 bludgeoning damage and be restrained by the tentacles until the spell ends. A creature that starts its turn in the area and is already restrained by the tentacles takes 3d6 bludgeoning damage.\n\nA creature restrained by the tentacles can use its action to make a Strength or Dexterity check (its choice) against your spell save DC. On a success, it frees itself.', classes: ['wizard'], damageType: 'bludgeoning', savingThrow: 'dex', tags: ['control', 'aoe'] },
  { id: 'freedom-of-movement', name: 'Freedom of Movement', level: 4, school: 'Abjuration', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'a leather strap, bound around the arm or a similar appendage', duration: '1 hour', concentration: false, ritual: false, description: 'You touch a willing creature. For the duration, the target\'s movement is unaffected by difficult terrain, and spells and other magical effects can neither reduce the target\'s speed nor cause the target to be paralyzed or restrained.\n\nThe target can also spend 5 feet of movement to automatically escape from nonmagical restraints, such as manacles or a creature that has it grappled. Finally, being underwater imposes no penalties on the target\'s movement or attacks.', classes: ['bard', 'cleric', 'druid', 'ranger'], tags: ['buff', 'movement'] },
  { id: 'ice-storm', name: 'Ice Storm', level: 4, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '300 feet', components: ['V', 'S', 'M'], materialComponent: 'a pinch of dust and a few drops of water', duration: 'Instantaneous', concentration: false, ritual: false, description: 'A hail of rock-hard ice pounds to the ground in a 20-foot-radius, 40-foot-high cylinder centered on a point within range. Each creature in the cylinder must make a Dexterity saving throw. A creature takes 2d8 bludgeoning damage and 4d6 cold damage on a failed save, or half as much damage on a successful one.\n\nHailstones turn the storm\'s area of effect into difficult terrain until the end of your next turn.\n\nAt Higher Levels: When you cast this spell using a spell slot of 5th level or higher, the bludgeoning damage increases by 1d8 for each slot level above 4th.', atHigherLevels: 'Bludgeoning damage increases by 1d8 for each slot level above 4th.', classes: ['druid', 'sorcerer', 'wizard'], damageType: 'cold', savingThrow: 'dex', tags: ['damage', 'aoe'] },
  { id: 'stoneskin', name: 'Stoneskin', level: 4, school: 'Abjuration', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'diamond dust worth 100 gp, which the spell consumes', duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: 'This spell turns the flesh of a willing creature you touch as hard as stone. Until the spell ends, the target has resistance to nonmagical bludgeoning, piercing, and slashing damage.', classes: ['druid', 'ranger', 'sorcerer', 'wizard'], tags: ['defense', 'resistance'] },
  { id: 'wall-of-fire', name: 'Wall of Fire', level: 4, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '120 feet', components: ['V', 'S', 'M'], materialComponent: 'a small piece of phosphorus', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You create a wall of fire on a solid surface within range. The wall can be up to 60 feet long, 20 feet high, and 1 foot thick, or a ringed wall up to 20 feet in diameter, 20 feet high, and 1 foot thick. The wall is opaque and lasts for the duration.\n\nWhen the wall appears, each creature within its area must make a Dexterity saving throw. On a failed save, a creature takes 5d8 fire damage, or half as much damage on a successful save.\n\nOne side of the wall, selected by you when you cast this spell, deals 5d8 fire damage to each creature that ends its turn within 10 feet of that side or inside the wall. A creature takes the same damage when it enters the wall for the first time on a turn.\n\nAt Higher Levels: When you cast this spell using a spell slot of 5th level or higher, the damage increases by 1d8 for each slot level above 4th.', atHigherLevels: 'Damage increases by 1d8 for each slot level above 4th.', classes: ['druid', 'sorcerer', 'wizard'], damageType: 'fire', savingThrow: 'dex', tags: ['damage', 'control', 'aoe'] },

  // ── ADDITIONAL LEVEL 5 SPELLS ────────────────────────────────────────────
  { id: 'animate-objects', name: 'Animate Objects', level: 5, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: '120 feet', components: ['V', 'S'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'Objects come to life at your command. Choose up to ten nonmagical objects within range that are not being worn or carried. Medium targets count as two objects, Large targets count as four objects, Huge targets count as eight objects. You can\'t animate any object larger than Huge. Each target animates and becomes a creature under your control until the spell ends or until reduced to 0 hit points.\n\nAs a bonus action, you can mentally command any creature you made with this spell if the creature is within 500 feet of you.\n\nAt Higher Levels: If you cast this spell using a spell slot of 6th level or higher, you can animate two additional objects for each slot level above 5th.', atHigherLevels: 'Animate two additional objects for each slot level above 5th.', classes: ['bard', 'sorcerer', 'wizard'], tags: ['summoning', 'control'] },
  { id: 'dominate-person', name: 'Dominate Person', level: 5, school: 'Enchantment', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You attempt to beguile a humanoid that you can see within range. It must succeed on a Wisdom saving throw or be charmed by you for the duration. While the target is charmed, you have a telepathic link with it as long as the two of you are on the same plane of existence. You can use this telepathic link to issue commands to the creature while you are conscious (no action required), which it does its best to obey.\n\nAt Higher Levels: When you cast this spell using a 6th-level spell slot, the duration is 10 minutes. When you use a 7th-level spell slot, the duration is 1 hour. When you use a spell slot of 8th level or higher, the duration is 8 hours.', atHigherLevels: '6th level: 10 min. 7th level: 1 hour. 8th+: 8 hours.', classes: ['bard', 'sorcerer', 'wizard'], savingThrow: 'wis', tags: ['control', 'enchantment'] },
  { id: 'greater-restoration', name: 'Greater Restoration', level: 5, school: 'Abjuration', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'diamond dust worth at least 100 gp, which the spell consumes', duration: 'Instantaneous', concentration: false, ritual: false, description: 'You imbue a creature you touch with positive energy to undo a debilitating effect. You can reduce the target\'s exhaustion level by one, or end one of the following effects on the target:\n\n• One effect that charmed or petrified the target\n• One curse, including the target\'s attunement to a cursed magic item\n• Any reduction to one of the target\'s ability scores\n• One effect reducing the target\'s hit point maximum', classes: ['bard', 'cleric', 'druid'], tags: ['healing', 'utility'] },
  { id: 'hold-monster', name: 'Hold Monster', level: 5, school: 'Enchantment', sourceBook: 'PHB', castingTime: '1 action', range: '90 feet', components: ['V', 'S', 'M'], materialComponent: 'a small, straight piece of iron', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'Choose a creature that you can see within range. The target must succeed on a Wisdom saving throw or be paralyzed for the duration. This spell has no effect on undead. At the end of each of its turns, the target can make another Wisdom saving throw. On a success, the spell ends on the target.\n\nAt Higher Levels: When you cast this spell using a spell slot of 6th level or higher, you can target one additional creature for each slot level above 5th.', atHigherLevels: 'Target one additional creature for each slot level above 5th.', classes: ['bard', 'sorcerer', 'warlock', 'wizard'], savingThrow: 'wis', tags: ['control', 'paralysis'] },
  { id: 'raise-dead', name: 'Raise Dead', level: 5, school: 'Necromancy', sourceBook: 'PHB', castingTime: '1 hour', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'a diamond worth at least 500 gp, which the spell consumes', duration: 'Instantaneous', concentration: false, ritual: false, description: 'You return a dead creature you touch to life, provided that it has been dead no longer than 10 days. If the creature\'s soul is both willing and at liberty to rejoin the body, the creature returns to life with 1 hit point.\n\nThis spell also neutralizes any poisons and cures nonmagical diseases that affected the creature at the time it died. This spell doesn\'t, however, remove magical diseases, curses, or similar effects; if these aren\'t first removed prior to casting the spell, they take effect when the creature returns to life.\n\nThe spell can\'t return an undead creature to life.\n\nComing back from the dead is an ordeal. The target takes a −4 penalty to all attack rolls, saving throws, and ability checks. Every time the target finishes a long rest, the penalty is reduced by 1 until it disappears.', classes: ['bard', 'cleric', 'paladin'], tags: ['healing', 'necromancy'] },
  { id: 'scrying', name: 'Scrying', level: 5, school: 'Divination', sourceBook: 'PHB', castingTime: '10 minutes', range: 'Self', components: ['V', 'S', 'M'], materialComponent: 'a focus worth at least 1,000 gp, such as a crystal ball, a silver mirror, or a font filled with holy water', duration: 'Concentration, up to 10 minutes', concentration: true, ritual: false, description: 'You can see and hear a particular creature you choose that is on the same plane of existence as you. The target must make a Wisdom saving throw, which is modified by how well you know the target and the sort of physical connection you have to it.\n\nOn a successful save, the target isn\'t affected, and you can\'t use this spell against it again for 24 hours.\n\nOn a failed save, the spell creates an invisible sensor within 10 feet of the target. You can see and hear through the sensor as if you were there. The sensor moves with the target, remaining within 10 feet of it for the duration.', classes: ['bard', 'cleric', 'druid', 'warlock', 'wizard'], savingThrow: 'wis', tags: ['utility', 'detection', 'divination'] },
  { id: 'steel-wind-strike', name: 'Steel Wind Strike', level: 5, school: 'Conjuration', sourceBook: 'XGtE', castingTime: '1 action', range: '30 feet', components: ['S', 'M'], materialComponent: 'a melee weapon worth at least 1 sp', duration: 'Instantaneous', concentration: false, ritual: false, description: 'You flourish the weapon used in the casting and then vanish to strike like the wind. Choose up to five creatures you can see within range. Make a melee spell attack against each target. On a hit, a target takes 6d10 force damage.\n\nYou can then teleport to an unoccupied space you can see within 5 feet of one of the targets you hit or missed.', classes: ['ranger', 'wizard'], damageType: 'force', tags: ['damage', 'teleportation'] },
  { id: 'telekinesis', name: 'Telekinesis', level: 5, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S'], duration: 'Concentration, up to 10 minutes', concentration: true, ritual: false, description: 'You gain the ability to move or manipulate creatures or objects by thought. When you cast the spell, and as your action each round for the duration, you can exert your will on one creature or object that you can see within range, causing the appropriate effect below.\n\nCreature: You can try to move a Huge or smaller creature. Make an ability check with your spellcasting ability contested by the creature\'s Strength check. If you win the contest, you move the creature up to 30 feet in any direction, including upward but not beyond the range of this spell. Until the end of your next turn, the creature is restrained in your telekinetic grip.\n\nObject: You can try to move an object that weighs up to 1,000 pounds.', classes: ['sorcerer', 'wizard'], tags: ['control', 'utility'] },
];

export function getSpell(id: string): Spell | undefined {
  return ALL_SPELLS.find(s => s.id === id);
}

export function getSpellsByClass(classId: string): Spell[] {
  return ALL_SPELLS.filter(s => s.classes.includes(classId));
}
